// Inicializa OneSignal e identifica al usuario
async function registerPushNotifications(user) {
  try {
    await window.OneSignalDeferred?.push(async (os) => {
      await os.init({
        appId: ONESIGNAL_APP_ID,
        allowLocalhostAsSecureOrigin: true,
        promptOptions: { slidedown: { prompts: [{ type: "push", autoPrompt: true, text: { actionMessage: "El Coro MJ quiere enviarte avisos y novedades.", acceptButton: "Activar", cancelButton: "Ahora no" } }] } },
      });
    });
    // Identificar al usuario en OneSignal con su ID
    if (user?.id) {
      await window.OneSignalDeferred?.push((os) => os.login(user.id));
    }
    await window.OneSignalDeferred?.push((os) => os.Notifications.requestPermission());
    return true;
  } catch (e) {
    console.warn("OneSignal register error:", e);
    return false;
  }
}

async function unregisterPushNotifications(userId) {
  try {
    await window.OneSignalDeferred?.push((os) => os.User.PushSubscription.optOut());
    if (userId) {
      await window.OneSignalDeferred?.push((os) => os.logout());
    }
  } catch (e) { console.warn("OneSignal unregister error:", e); }
}

async function checkPushSubscribed() {
  try {
    let enabled = false;
    await window.OneSignalDeferred?.push((os) => {
      enabled = os.User.PushSubscription.optedIn === true;
    });
    return enabled;
  } catch { return false; }
}

// Envía notificación a TODOS los suscritos.
// Llama a la función de servidor /api/send-push (que a su vez habla con OneSignal).
// El navegador NO puede llamar a OneSignal directamente (CORS), por eso pasa por el servidor.
async function sendPushToAll(title, body, url = "/") {
  try {
    const res = await fetch("/api/send-push", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ title, body, url }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data?.ok === false) {
      console.error("Error enviando push:", data);
      return { ok: false, data };
    }
    console.log("Push enviada. Destinatarios:", data?.recipients);
    return { ok: true, recipients: data?.recipients };
  } catch (e) {
    console.error("Error enviando push (red):", e);
    return { ok: false, error: String(e) };
  }
}

// ── Detección de dispositivo para instrucciones de notificaciones ──
function detectarDispositivo() {
  if (typeof navigator === "undefined") return "desktop";
  const ua = navigator.userAgent || "";
  const esIOS = /iPad|iPhone|iPod/.test(ua) || (navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1);
  const esAndroid = /Android/.test(ua);
  if (esIOS) return "ios";
  if (esAndroid) return "android";
  return "desktop";
}
// ¿La app está abierta como app instalada (PWA) y no en el navegador?
function estaInstalada() {
  if (typeof window === "undefined") return false;
  return (
    window.matchMedia?.("(display-mode: standalone)")?.matches ||
    window.navigator.standalone === true
  );
}

// ── Google Calendar API (pública, solo lectura) ───────────────────────
const GCAL_CALENDAR_ID = "coromisionerosdjesuscl@gmail.com";
const GCAL_API_KEY = "AIzaSyAFSJguKkIY1shCYA1HIFwv9OtaYGnu45k";

async function fetchGoogleCalendarEvents() {
  try {
    const now = new Date().toISOString();
    const calId = encodeURIComponent(GCAL_CALENDAR_ID);
    const url = `https://www.googleapis.com/calendar/v3/calendars/${calId}/events?key=${GCAL_API_KEY}&timeMin=${now}&maxResults=20&singleEvents=true&orderBy=startTime`;
    const res = await fetch(url, {
      signal: (() => {
        const c = new AbortController();
        setTimeout(() => c.abort(), 8000);
        return c.signal;
      })(),
    });
    if (!res.ok) return [];
    const data = await res.json();
    return (data.items || []).map((item) => {
      const start = item.start?.dateTime || item.start?.date || "";
      const isDateTime = !!item.start?.dateTime;
      const fecha = start.split("T")[0];
      const hora = isDateTime
        ? new Date(item.start.dateTime).toLocaleTimeString("es-CL", {
            hour: "2-digit",
            minute: "2-digit",
            hour12: false,
          })
        : "";
      const titulo = item.summary || "Sin título";
      const tl = titulo.toLowerCase();
      const tipo = tl.includes("ensayo")
        ? "ensayo"
        : tl.includes("misa") ||
          tl.includes("vigilia") ||
          tl.includes("corpus") ||
          tl.includes("pentecost") ||
          tl.includes("pascua")
        ? "misa"
        : "evento";
      return {
        id: item.id,
        titulo,
        fecha,
        hora,
        tipo,
        lugar: item.location || "",
        descripcion: item.description || "",
      };
    });
  } catch (e) {
    console.warn("Error cargando Google Calendar:", e);
    return [];
  }
}

// Token de sesión activo (se actualiza al hacer login)
let _authToken = null;
let _refreshToken = null;
let _anthropicKey = ""; // Se carga desde Supabase config al iniciar sesión
let _isGuestSession = false; // true cuando entró con código de invitado (sin auth Supabase)

async function refreshSession() {
  if (!_refreshToken) return false;
  try {
    const res = await fetch(
      `${SUPABASE_URL}/auth/v1/token?grant_type=refresh_token`,
      {
        method: "POST",
        headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
        body: JSON.stringify({ refresh_token: _refreshToken }),
      }
    );
    if (!res.ok) return false;
    const data = await res.json();
    _authToken = data.access_token;
    _refreshToken = data.refresh_token;
    // Persistir en localStorage para sobrevivir recargas
    localStorage.setItem("sb_access_token", data.access_token);
    localStorage.setItem("sb_refresh_token", data.refresh_token);
    return true;
  } catch {
    return false;
  }
}

// Intentar restaurar sesión desde localStorage al cargar
(function restoreSession() {
  const at = localStorage.getItem("sb_access_token");
  const rt = localStorage.getItem("sb_refresh_token");
  if (at) _authToken = at;
  if (rt) _refreshToken = rt;
})();

async function supabase(table, options = {}) {
  const {
    method = "GET",
    body,
    select = "*",
    filters = "",
    order = "",
  } = options;
  let url = `${SUPABASE_URL}/rest/v1/${table}?select=${select}${filters}${order}`;
  const makeHeaders = () => ({
    apikey: SUPABASE_KEY,
    Authorization: `Bearer ${_isGuestSession ? SUPABASE_SERVICE_KEY : (_authToken || SUPABASE_KEY)}`,
    "Content-Type": "application/json",
    Prefer: method === "POST" ? "return=representation" : "",
  });
  let res = await fetch(url, {
    method,
    headers: makeHeaders(),
    body: body ? JSON.stringify(body) : undefined,
  });
  // Si JWT expiró, intentar renovar y reintentar una vez
  if (res.status === 401) {
    const refreshed = await refreshSession();
    if (refreshed) {
      res = await fetch(url, {
        method,
        headers: makeHeaders(),
        body: body ? JSON.stringify(body) : undefined,
      });
    }
  }
  if (!res.ok) throw new Error(await res.text());
  return res.status === 204 ? null : res.json();
}

// Renovar token automáticamente cada 50 minutos (expira en 1 hora)
setInterval(() => {
  if (_refreshToken) refreshSession();
}, 50 * 60 * 1000);
async function authSignUp(email, password, nombre, cuerda, cumpleanos, genero, aprobadoDirecto) {
  nombre = formatoNombre(nombre);
  const res = await fetch(`${SUPABASE_URL}/auth/v1/signup`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ email, password, data: { nombre, cuerda } }),
  });
  const data = await res.json();
  if (!res.ok)
    throw new Error(data.msg || data.message || "Error al registrar");
  if (!data.access_token)
    throw new Error(
      "Cuenta creada. Revisa tu correo para confirmarla antes de ingresar."
    );
  _authToken = data.access_token;
  _refreshToken = data.refresh_token;
  localStorage.setItem("sb_access_token", data.access_token);
  localStorage.setItem("sb_refresh_token", data.refresh_token);
  const uid = data.user?.id;
  const esAprobado = aprobadoDirecto === true; // solo con código de admin
  await fetch(`${SUPABASE_URL}/rest/v1/integrantes`, {
    method: "POST",
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${_authToken}`,
      "Content-Type": "application/json",
      Prefer: "return=representation",
    },
    body: JSON.stringify({
      nombre,
      email,
      cuerda: esAprobado ? (cuerda || "Admin") : "",
      cuerda_solicitada: esAprobado ? "" : (cuerda || ""),
      acceso: esAprobado ? "aprobado" : "pendiente",
      cumpleanos: cumpleanos || "",
      genero: genero || "",
      auth_id: uid,
    }),
  });
  return data;
}

async function authSignIn(email, password) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ email, password }),
  });
  const data = await res.json();
  if (!res.ok)
    throw new Error(
      data.error_description || data.msg || "Credenciales incorrectas"
    );
  _authToken = data.access_token;
  _refreshToken = data.refresh_token;
  localStorage.setItem("sb_access_token", data.access_token);
  localStorage.setItem("sb_refresh_token", data.refresh_token);
  return data;
}

async function authResetPassword(email) {
  const redirectTo = "https://portal-coro-mj.vercel.app/?type=recovery";
  const res = await fetch(`${SUPABASE_URL}/auth/v1/recover`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ email, gotrue_meta_security: {}, redirect_to: redirectTo }),
  });
  if (!res.ok) {
    const d = await res.json();
    throw new Error(d.msg || "Error");
  }
}

async function authUpdatePassword(newPassword) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/user`, {
    method: "PUT",
    headers: {
      apikey: SUPABASE_KEY,
      "Content-Type": "application/json",
      Authorization: `Bearer ${_authToken}`,
    },
    body: JSON.stringify({ password: newPassword }),
  });
  if (!res.ok) {
    const d = await res.json();
    throw new Error(d.msg || "Error al actualizar contraseña");
  }
}

async function authSignOut() {
  if (!_authToken) return;
  await fetch(`${SUPABASE_URL}/auth/v1/logout`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${_authToken}` },
  });
  _authToken = null;
  _refreshToken = null;
  localStorage.removeItem("sb_access_token");
  localStorage.removeItem("sb_refresh_token");
}

