const CUERDAS = {
  Soprano: "#ec4899",
  Contralto: "#0e7490",
  Tenor: "#3b82f6",
  Bajo: "#1e3a5f",
  Admin: "#6b7280",
  "Contador/a Coro": "#f59e0b",
  Visita: "#0ea5e9",
};
const rolLabel = (r, genero) => {
  if (r === "Admin") return genero === "F" ? "Encargada de Coro" : "Encargado de Coro";
  if (r === "Contador/a Coro") return genero === "F" ? "Contadora Coro" : "Contador Coro";
  return r || "";
};
// Detecta usuario Invitado por cargo (no toca la cuerda vocal)
const rolFullLabel = (m) => {
  if (!m) return "";
  if (esVisita(m)) return "";
  const cargo = m.cargo?.trim() || "";
  // Cuerda vocal real: para Admin/Contador usa cuerda_vocal, para el resto usa la cuerda directa
  const cuerdaVocal = (m.cuerda === "Admin" || m.cuerda === "Contador/a Coro")
    ? (m.cuerda_vocal?.trim() || "")
    : (m.cuerda?.trim() || "");
  const rolBase = rolLabel(m.cuerda, m.genero); // "Encargado de Coro", "Soprano", etc.

  if (m.cuerda === "Admin" || m.cuerda === "Contador/a Coro") {
    // Ej: "Encargado de Coro | Tenor"  o si tiene cargo extra: "Redes Sociales | Tenor"
    const left = cargo || rolBase;
    const right = cuerdaVocal;
    if (left && right) return `${left} | ${right}`;
    return left || right;
  }

  // Miembro normal con cargo extra: "Redes Sociales | Soprano"
  if (cargo && cuerdaVocal) return `${cargo} | ${cuerdaVocal}`;
  // Sin cargo extra: solo la cuerda
  return rolBase;
};
const ini = (n) =>
  n
    .split(" ")
    .map((x) => x[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();
const hoyDDMM = () => {
  const d = new Date();
  return `${String(d.getDate()).padStart(2, "0")}/${String(
    d.getMonth() + 1
  ).padStart(2, "0")}`;
};
const fmtFecha = (f) =>
  new Date(f + "T00:00:00").toLocaleDateString("es-CL", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });

