// ── Twitter Timeline Embed ─────────────────────────────
function TwitterTimeline() {
  const ref = useRef(null);
  useEffect(() => {
    if (!ref.current) return;
    ref.current.innerHTML = "";
    const anchor = document.createElement("a");
    anchor.className = "twitter-timeline";
    anchor.setAttribute("data-lang", "es");
    anchor.setAttribute("data-height", "320");
    anchor.setAttribute("data-theme", "light");
    anchor.setAttribute("data-chrome", "noheader nofooter noborders");
    anchor.href = "https://twitter.com/vaticannews_es";
    ref.current.appendChild(anchor);
    const script = document.createElement("script");
    script.src = "https://platform.twitter.com/widgets.js";
    script.async = true;
    script.charset = "utf-8";
    ref.current.appendChild(script);
  }, []);
  return <div ref={ref} style={{ background: "#ffffff", minHeight: 280 }} />;
}

function getSpotifyEmbedUrl(url) {
  if (!url) return null;
  if (!url.includes("spotify.com")) return null;
  // Limpiar parámetros y convertir a embed
  const clean = url.split("?")[0];
  return clean
    .replace("https://open.spotify.com/episode/", "https://open.spotify.com/embed/episode/")
    .replace("https://open.spotify.com/show/", "https://open.spotify.com/embed/show/")
    .replace("https://open.spotify.com/track/", "https://open.spotify.com/embed/track/");
}

function PodcastWidget({ podcasts, setSection }) {
  // Ordenar por campo "orden" asc — el admin controla cuál aparece primero en el widget
  const lista = podcasts && podcasts.length > 0
    ? [...podcasts].sort((a, b) => {
        const oa = a.orden ?? 999;
        const ob = b.orden ?? 999;
        if (oa !== ob) return oa - ob;
        return new Date(a.created_at) - new Date(b.created_at);
      })
    : null;
  const [idx, setIdx] = useState(0);
  const [playerOpen, setPlayerOpen] = useState(false);
  if (!lista) return null;
  const p = lista[Math.min(idx, lista.length - 1)];
  const embedUrl = getSpotifyEmbedUrl(p.url);

  function handleNav(newIdx) {
    setIdx(newIdx);
    setPlayerOpen(false);
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <span style={{ fontSize: 13 }}>🎙️</span>
        <span style={{ fontSize: 13, fontWeight: 600, color: C.dark }}>Podcast</span>
        <button
          onClick={() => setSection("podcast")}
          style={{ marginLeft: "auto", fontSize: 11, color: C.primary, background: "none", border: "none", cursor: "pointer", fontWeight: 500 }}
        >
          Ver todos →
        </button>
      </div>

      {/* Episodio */}
      <div style={{ background: C.primaryLight, borderRadius: 14, overflow: "hidden" }}>
        {/* Fila del episodio */}
        <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 12px" }}>
          <div style={{
            width: 42, height: 42, borderRadius: 12, flexShrink: 0,
            background: `linear-gradient(135deg,${C.primary},${C.primaryDark})`,
            display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18,
          }}>🎙️</div>

          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ fontSize: 12, fontWeight: 600, color: C.dark, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
              {p.titulo}
            </div>
            {p.autor && (
              <div style={{ fontSize: 11, color: C.gray, marginTop: 2 }}>👤 {p.autor}</div>
            )}
          </div>

          {/* Controles */}
          <div style={{ display: "flex", alignItems: "center", gap: 6, flexShrink: 0 }}>
            {lista.length > 1 && (
              <>
                <button onClick={() => handleNav(Math.max(0, idx - 1))} disabled={idx === 0}
                  style={{
                    width: 36, height: 36, borderRadius: 12,
                    border: `1px solid ${idx === 0 ? C.border : C.primary}`,
                    background: idx === 0 ? C.light : C.primaryLight,
                    cursor: idx === 0 ? "default" : "pointer",
                    color: idx === 0 ? C.border : C.primary,
                    fontSize: 20, display: "flex", alignItems: "center", justifyContent: "center",
                    flexShrink: 0, transition: "all 0.15s",
                  }}>‹</button>
                <span style={{ fontSize: 10, color: C.gray, minWidth: 28, textAlign: "center" }}>{idx + 1}/{lista.length}</span>
                <button onClick={() => handleNav(Math.min(lista.length - 1, idx + 1))} disabled={idx === lista.length - 1}
                  style={{
                    width: 36, height: 36, borderRadius: 12,
                    border: `1px solid ${idx === lista.length - 1 ? C.border : C.primary}`,
                    background: idx === lista.length - 1 ? C.light : C.primaryLight,
                    cursor: idx === lista.length - 1 ? "default" : "pointer",
                    color: idx === lista.length - 1 ? C.border : C.primary,
                    fontSize: 20, display: "flex", alignItems: "center", justifyContent: "center",
                    flexShrink: 0, transition: "all 0.15s",
                  }}>›</button>
              </>
            )}
            {p.url && (
              embedUrl ? (
                // Spotify: toggle player inline
                <button
                  onClick={() => setPlayerOpen(o => !o)}
                  title={playerOpen ? "Cerrar player" : "Reproducir en esta página"}
                  style={{
                    width: 36, height: 36, borderRadius: "50%",
                    background: playerOpen ? "#1DB954" : C.primary,
                    border: "none", cursor: "pointer",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    color: "white", fontSize: 14, marginLeft: 4,
                    transition: "background 0.2s",
                  }}
                >
                  {playerOpen ? "⏹" : "▶"}
                </button>
              ) : (
                // Otro servicio: abrir en nueva pestaña
                <a href={p.url} target="_blank" rel="noopener">
                  <div style={{
                    width: 36, height: 36, borderRadius: "50%",
                    background: C.primary, display: "flex", alignItems: "center",
                    justifyContent: "center", color: "white", fontSize: 14, marginLeft: 4,
                  }}>▶</div>
                </a>
              )
            )}
          </div>
        </div>

        {/* Spotify embed — se despliega al pulsar ▶ */}
        {playerOpen && embedUrl && (
          <div style={{ padding: "0 10px 10px" }}>
            <iframe
              src={`${embedUrl}?utm_source=generator&theme=0`}
              width="100%"
              height="152"
              frameBorder="0"
              allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture"
              loading="lazy"
              style={{ borderRadius: 12, display: "block" }}
              title={p.titulo}
            />
          </div>
        )}
      </div>
    </div>
  );
}

