// ══════════════════════════════════════════════════════════════════════
//  ADMINISTRACIÓN DE NOTIFICACIONES PUSH
// ══════════════════════════════════════════════════════════════════════
function AdminNotificaciones() {
  const [totalSubs, setTotalSubs] = useState(null);
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [form, setForm] = useState({ titulo: "", cuerpo: "" });
  const [msg, setMsg] = useState(null);

  useEffect(() => { cargar(); }, []);

  async function cargar() {
    setLoading(true);
    try {
      const res = await fetch(`https://api.onesignal.com/apps/${ONESIGNAL_APP_ID}`, {
        headers: { Authorization: `Key ${ONESIGNAL_API_KEY}` },
      });
      const data = await res.json();
      setTotalSubs(data.players ?? 0);
    } catch (e) { setTotalSubs(0); }
    setLoading(false);
  }

  async function enviarNotificacion() {
    if (!form.titulo) return;
    setSending(true);
    setMsg(null);
    try {
      const res = await fetch("https://api.onesignal.com/notifications", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Key ${ONESIGNAL_API_KEY}`,
        },
        body: JSON.stringify({
          app_id: ONESIGNAL_APP_ID,
          included_segments: ["Total Subscriptions"],
          headings: { en: form.titulo, es: form.titulo },
          contents: { en: form.cuerpo || form.titulo, es: form.cuerpo || form.titulo },
          url: "https://portal-coro-mj.vercel.app/",
        }),
      });
      const data = await res.json();
      if (data.errors) throw new Error(JSON.stringify(data.errors));
      setMsg({ ok: true, text: `✅ Notificación enviada a ${data.recipients ?? totalSubs} dispositivo(s).` });
      setForm({ titulo: "", cuerpo: "" });
    } catch (e) {
      setMsg({ ok: false, text: "❌ Error: " + e.message });
    }
    setSending(false);
  }

  const inputS = { padding: "8px 10px", borderRadius: 10, border: `1px solid ${C.border}`, fontSize: 13, outline: "none", width: "100%", boxSizing: "border-box" };

  return (
    <div>
      <div style={{ fontWeight: 700, fontSize: 16, color: C.dark, marginBottom: 4 }}>🔔 Notificaciones Push</div>
      <div style={{ fontSize: 12, color: C.gray, marginBottom: 20 }}>Envía avisos instantáneos a todos los integrantes que activaron notificaciones.</div>

      {/* Stats */}
      <div style={{ display: "flex", gap: 12, marginBottom: 24 }}>
        <div style={{ background: C.primary + "12", border: `1px solid ${C.primary}30`, borderRadius: 14, padding: "14px 18px", flex: 1 }}>
          <div style={{ fontSize: 24 }}>📱</div>
          <div style={{ fontSize: 28, fontWeight: 800, color: C.primary, marginTop: 4 }}>
            {loading ? "..." : totalSubs}
          </div>
          <div style={{ fontSize: 11, color: C.gray, marginTop: 2 }}>Dispositivos suscritos</div>
        </div>
        <div style={{ background: "#f0fdf4", border: "1px solid #86efac", borderRadius: 14, padding: "14px 18px", flex: 1, display: "flex", flexDirection: "column", justifyContent: "center" }}>
          <div style={{ fontSize: 11, color: "#15803d", fontWeight: 600, marginBottom: 4 }}>✅ OneSignal activo</div>
          <div style={{ fontSize: 10, color: C.gray, lineHeight: 1.5 }}>Las notificaciones llegan directamente al teléfono aunque el usuario no tenga la app abierta.</div>
        </div>
      </div>

      {/* Formulario envío manual */}
      <div style={{ background: C.primaryLight, border: `1px solid ${C.primary}40`, borderRadius: 14, padding: "18px 20px", marginBottom: 24 }}>
        <div style={{ fontWeight: 700, fontSize: 14, color: C.dark, marginBottom: 14 }}>📤 Enviar notificación</div>
        <div style={{ marginBottom: 10 }}>
          <div style={{ fontSize: 11, color: C.gray, marginBottom: 4 }}>Título *</div>
          <input placeholder="Ej: Ensayo cancelado" value={form.titulo} onChange={e => setForm(p => ({ ...p, titulo: e.target.value }))} style={inputS} />
        </div>
        <div style={{ marginBottom: 14 }}>
          <div style={{ fontSize: 11, color: C.gray, marginBottom: 4 }}>Mensaje (opcional)</div>
          <textarea placeholder="Detalles de la notificación..." value={form.cuerpo} onChange={e => setForm(p => ({ ...p, cuerpo: e.target.value }))} rows={3}
            style={{ ...inputS, resize: "vertical", fontFamily: "Inter,sans-serif" }} />
        </div>
        {msg && (
          <div style={{ marginBottom: 12, padding: "10px 14px", borderRadius: 10, background: msg.ok ? "#dcfce7" : "#fee2e2", color: msg.ok ? "#15803d" : "#dc2626", fontSize: 13, fontWeight: 600 }}>
            {msg.text}
          </div>
        )}
        <Btn onClick={enviarNotificacion} disabled={sending || !form.titulo}>
          {sending ? "Enviando..." : `🔔 Enviar a todos (${loading ? "..." : totalSubs} dispositivos)`}
        </Btn>
      </div>

      {/* Info OneSignal */}
      <div style={{ background: "#f8faff", border: `1px solid #c7d7f9`, borderRadius: 14, padding: "14px 18px" }}>
        <div style={{ fontWeight: 600, fontSize: 13, color: "#3b5bdb", marginBottom: 8 }}>ℹ️ Cómo funciona</div>
        <div style={{ fontSize: 12, color: C.gray, lineHeight: 1.8 }}>
          • Los integrantes activan las notificaciones desde <strong>Mi Perfil → Notificaciones</strong>.<br />
          • OneSignal gestiona automáticamente todos los dispositivos suscritos.<br />
          • Las notificaciones llegan aunque el teléfono esté bloqueado.<br />
          • También puedes enviar desde <strong>onesignal.com</strong> con más opciones (programar, segmentar, etc.).
        </div>
      </div>
    </div>
  );
}

