// ── Helpers exclusivos del módulo Finanzas ────────────────────────────
function finGetToken() {
  return localStorage.getItem("sb_access_token") || SUPABASE_KEY;
}
async function registrarVisita(user, token) {
  if (!user) return;
  try {
    await fetch(`${SUPABASE_URL}/rest/v1/visitas_sitio`, {
      method: "POST",
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: `Bearer ${token || SUPABASE_KEY}`,
        "Content-Type": "application/json",
        Prefer: "return=minimal",
      },
      body: JSON.stringify({
        integrante_id: user.id || null,
        nombre: user.nombre || "Desconocido",
        email: user.email || null,
        cuerda: user.cuerda || null,
      }),
    });
  } catch (e) {
    // Silencioso — no afecta el flujo de login
  }
}
async function finDbGet(table, filters = "") {
  const res = await fetch(
    `${SUPABASE_URL}/rest/v1/${table}?select=*${filters}&order=created_at.desc`,
    { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${finGetToken()}` } }
  );
  if (!res.ok) throw new Error(await res.text());
  return res.json();
}
async function finDbPost(table, body) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${finGetToken()}`, "Content-Type": "application/json", Prefer: "return=representation" },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(await res.text());
  return res.json();
}
async function finDbPatch(table, id, body) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?id=eq.${id}`, {
    method: "PATCH",
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${finGetToken()}`, "Content-Type": "application/json", Prefer: "return=representation" },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(await res.text());
}
async function finDbDelete(table, id) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?id=eq.${id}`, {
    method: "DELETE",
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${finGetToken()}` },
  });
  if (!res.ok) throw new Error(await res.text());
}
async function finUploadFile(bucket, path, file) {
  const res = await fetch(`${SUPABASE_URL}/storage/v1/object/${bucket}/${path}`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${finGetToken()}`, "Content-Type": file.type },
    body: file,
  });
  if (!res.ok) throw new Error(await res.text());
  return `${SUPABASE_URL}/storage/v1/object/public/${bucket}/${path}`;
}
const finFmtCLP = (n) => new Intl.NumberFormat("es-CL", { style: "currency", currency: "CLP" }).format(n || 0);
const FIN_MESES = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];
function finMesLabel(iso) { const [y, m] = iso.split("-"); return `${FIN_MESES[parseInt(m) - 1]} ${y}`; }
function finCurrentMesIso() { const d = new Date(); return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`; }

function mostrarToastCopia(msg) {
  try {
    const t = document.createElement("div");
    t.textContent = msg;
    t.style.cssText = "position:fixed;bottom:30px;left:50%;transform:translateX(-50%);background:#1c1c1e;color:#fff;padding:10px 18px;border-radius:12px;font-size:14px;font-weight:600;z-index:99999;box-shadow:0 6px 24px rgba(0,0,0,0.28);opacity:0;transition:opacity .15s";
    document.body.appendChild(t);
    requestAnimationFrame(() => { t.style.opacity = "1"; });
    setTimeout(() => { t.style.opacity = "0"; setTimeout(() => { try { t.remove(); } catch (e) {} }, 220); }, 1200);
  } catch (e) {}
}
function fallbackCopiar(text) {
  try {
    const ta = document.createElement("textarea");
    ta.value = text;
    ta.style.position = "fixed";
    ta.style.top = "-9999px";
    ta.contentEditable = "true";
    ta.readOnly = false;
    document.body.appendChild(ta);
    const range = document.createRange();
    range.selectNodeContents(ta);
    const sel = window.getSelection();
    sel.removeAllRanges();
    sel.addRange(range);
    ta.setSelectionRange(0, 999999);
    const ok = document.execCommand("copy");
    document.body.removeChild(ta);
    return ok;
  } catch (e) { return false; }
}
function copiarTexto(text) {
  if (navigator.clipboard && navigator.clipboard.writeText && window.isSecureContext) {
    navigator.clipboard.writeText(text)
      .then(() => mostrarToastCopia("✓ Copiado"))
      .catch(() => mostrarToastCopia(fallbackCopiar(text) ? "✓ Copiado" : "No se pudo copiar"));
  } else {
    mostrarToastCopia(fallbackCopiar(text) ? "✓ Copiado" : "No se pudo copiar");
  }
}

const CUOTA_ESTUDIANTE_MONTO = 3000; // Valor fijo cuota estudiante
const CUOTAS_MES_INICIO = "2026-06"; // Las cuotas empiezan en Junio 2026
function finMesVigente() { return finCurrentMesIso() >= CUOTAS_MES_INICIO; }
const finIni = (n) => (n || "?").charAt(0).toUpperCase();
const finCuerdaLabel = (c, genero) => c === "Admin" ? rolLabel("Admin", genero) : c === "Contador/a Coro" ? rolLabel("Contador/a Coro", genero) : (c || "");

// ── Micro componentes ──────────────────────────────────────────────────
function FinCard({ children, style = {} }) {
  return (
    <div
      style={{
        background: "rgba(255,255,255,0.95)",
        borderRadius: 20,
        border: "1px solid rgba(60,60,67,0.09)",
        padding: "18px 20px",
        boxShadow: "0 1px 4px rgba(0,0,0,0.05), 0 4px 16px rgba(0,0,0,0.05)",
        backdropFilter: "blur(12px)",
        WebkitBackdropFilter: "blur(12px)",
        ...style,
      }}
    >
      {children}
    </div>
  );
}

function FinBtn({ children, onClick, variant = "primary", disabled = false, style = {} }) {
  const [h, setH] = useState(false);
  const [pressed, setPressed] = useState(false);
  const bg =
    variant === "primary"
      ? h ? `linear-gradient(135deg, ${C.primaryDark} 0%, #1a2d4a 100%)` : `linear-gradient(135deg, ${C.primary} 0%, #0f3d6e 100%)`
      : variant === "danger"
      ? h ? "#dc2626" : "#ef4444"
      : variant === "ghost"
      ? h ? "rgba(0,0,0,0.07)" : "rgba(0,0,0,0.04)"
      : h ? "rgba(0,0,0,0.09)" : "rgba(0,0,0,0.05)";
  const color =
    variant === "primary" || variant === "danger" ? "white" : C.dark;
  const shadow =
    variant === "primary" ? `0 2px 10px ${C.primary}40`
    : variant === "danger" ? "0 2px 10px rgba(239,68,68,0.35)"
    : "none";
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      onMouseEnter={() => setH(true)}
      onMouseLeave={() => { setH(false); setPressed(false); }}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: 6,
        padding: "8px 16px",
        borderRadius: 12,
        border: variant === "ghost" ? `1px solid rgba(60,60,67,0.16)` : "none",
        cursor: disabled ? "not-allowed" : "pointer",
        fontSize: 13,
        fontWeight: 600,
        letterSpacing: "-0.01em",
        background: bg,
        color,
        opacity: disabled ? 0.5 : 1,
        boxShadow: disabled ? "none" : shadow,
        transform: pressed && !disabled ? "scale(0.97)" : "scale(1)",
        transition: "all 0.16s cubic-bezier(0.25,0.46,0.45,0.94)",
        WebkitTapHighlightColor: "transparent",
        ...style,
      }}
    >
      {children}
    </button>
  );
}

