function TabBtn({ label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      style={{
        padding: "8px 16px",
        borderRadius: 20,
        border: active ? "none" : "1px solid rgba(60,60,67,0.15)",
        cursor: "pointer",
        fontSize: 13,
        fontWeight: active ? 600 : 500,
        background: active
          ? `linear-gradient(135deg, ${C.primary} 0%, #0f3d6e 100%)`
          : "rgba(255,255,255,0.8)",
        color: active ? "white" : C.gray,
        boxShadow: active ? `0 2px 10px ${C.primary}40` : "none",
        whiteSpace: "nowrap",
        letterSpacing: "-0.01em",
        transition: "all 0.18s cubic-bezier(0.25,0.46,0.45,0.94)",
        WebkitTapHighlightColor: "transparent",
      }}
    >
      {label}
    </button>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  HOOKS
// ══════════════════════════════════════════════════════════════════════

function useFinanzasData() {
  const [cuotas, setCuotas] = useState([]);
  const [pagos, setPagos] = useState([]);
  const [actividades, setActividades] = useState([]);
  const [gastos, setGastos] = useState([]);
  const [miembrosEnCuotas, setMiembrosEnCuotas] = useState([]);
  const [loading, setLoading] = useState(true);

  const reload = useCallback(async () => {
    setLoading(true);
    try {
      const [c, p, a, g, mc] = await Promise.all([
        finDbGet("fin_cuotas"),
        finDbGet("fin_pagos"),
        finDbGet("fin_actividades"),
        finDbGet("fin_gastos"),
        finDbGet("fin_miembros_cuotas"),
      ]);
      setCuotas(c || []);
      setPagos(p || []);
      setActividades(a || []);
      setGastos(g || []);
      setMiembrosEnCuotas(mc || []);
    } catch (e) {
      console.error("Error cargando finanzas:", e);
    }
    setLoading(false);
  }, []);

  useEffect(() => { reload(); }, [reload]);

  return { cuotas, pagos, actividades, gastos, miembrosEnCuotas, loading, reload };
}

// ══════════════════════════════════════════════════════════════════════
//  TAB: CUOTAS MENSUALES
// ══════════════════════════════════════════════════════════════════════

function TabCuotas({ members, cuotas, pagos, miembrosEnCuotas, reload, user }) {
  // Mes inicial: el mes actual, o el siguiente si ya es día 20+ (pago anticipado habilitado)
  const _initMes = (() => {
    const hoyI = new Date();
    const offset = hoyI.getDate() >= 20 ? 1 : 0;
    const d = new Date(hoyI.getFullYear(), hoyI.getMonth() + offset);
    const iso = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
    return iso >= "2026-06" ? iso : "2026-06";
  })();
  const [mesSeleccionado, setMesSeleccionado] = useState(_initMes);
  const [valorCuota, setValorCuota] = useState("");
  const [saving, setSaving] = useState(false);
  const [uploadingId, setUploadingId] = useState(null);
  const fileRefs = useRef({});

  // Miembros activos en sistema de cuotas
  const miembrosIds = new Set(miembrosEnCuotas.map((m) => m.integrante_id));
  const miembrosActivos = members.filter((m) => miembrosIds.has(m.id));

  // Helper: monto que debe pagar cada integrante según su tipo
  function montoParaMiembro(miembro) {
    const reg = miembrosEnCuotas.find((r) => r.integrante_id === miembro.id);
    return reg?.es_estudiante ? CUOTA_ESTUDIANTE_MONTO : (cuotaMes?.valor || 0);
  }

  // Cuota del mes seleccionado
  const cuotaMes = cuotas.find((c) => c.mes === mesSeleccionado);
  const pagosMes = pagos.filter((p) => p.mes === mesSeleccionado);

  const pagaron = new Set(pagosMes.map((p) => p.integrante_id));
  const totalEsperado = miembrosActivos.reduce((s, m) => s + montoParaMiembro(m), 0);
  const totalRecaudado = pagosMes.reduce((s, p) => s + (p.monto || 0), 0);

  // Meses disponibles para REGISTRAR PAGOS:
  // - Desde Junio 2026 hasta el mes actual (inclusive).
  // - A partir del día 20 de cada mes, también se habilita el mes siguiente
  //   (ya que la fecha de pago del mes siguiente vence el día 5).
  const mesesDisponibles = (() => {
    const hoyTemp = new Date();
    const diaHoy = hoyTemp.getDate();
    // Mes máximo permitido: si hoy >= día 20, se habilita el mes siguiente
    const mesMaxDate = new Date(hoyTemp.getFullYear(), hoyTemp.getMonth() + (diaHoy >= 20 ? 1 : 0));
    const mesMaxIso = `${mesMaxDate.getFullYear()}-${String(mesMaxDate.getMonth() + 1).padStart(2, "0")}`;
    return Array.from({ length: 55 }, (_, i) => {
      const d = new Date(2026, 5 + i); // Junio 2026 → Diciembre 2030
      return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
    }).filter((m) => m <= mesMaxIso);
  })();

  async function guardarValorCuota() {
    if (!valorCuota || isNaN(parseFloat(valorCuota))) return;
    setSaving(true);
    try {
      if (cuotaMes) {
        await finDbPatch("fin_cuotas", cuotaMes.id, { valor: parseFloat(valorCuota) });
      } else {
        await finDbPost("fin_cuotas", { mes: mesSeleccionado, valor: parseFloat(valorCuota) });
      }
      setValorCuota("");
      await reload();
    } catch (e) {
      alert("Error: " + e.message);
    }
    setSaving(false);
  }

  // ── Modales de confirmación de pago ──
  const [confirmPagar, setConfirmPagar]                   = useState(null); // { miembro }
  const [confirmBorrar, setConfirmBorrar]                 = useState(null); // { miembro, pago }
  const [confirmContadora, setConfirmContadora]           = useState(null); // { miembro } — pago propio de la contadora
  const [confirmPagarConComprobante, setConfirmPagarConComprobante] = useState(null); // { miembro } — modal explicativo antes de pedir archivo
  const [procesando, setProcesando]                       = useState(false);
  const [savingTipo, setSavingTipo]                       = useState(null);

  async function toggleTipoCuotas(miembro) {
    const reg = miembrosEnCuotas.find((r) => r.integrante_id === miembro.id);
    if (!reg) return;
    setSavingTipo(miembro.id);
    try {
      await finDbPatch("fin_miembros_cuotas", reg.id, { es_estudiante: !reg.es_estudiante });
      await reload();
    } catch (e) { alert("Error al cambiar tipo: " + e.message); }
    setSavingTipo(null);
  }

  async function togglePago(miembro) {
    if (pagaron.has(miembro.id)) {
      // Desmarcar → siempre pedir confirmación
      const pago = pagosMes.find((p) => p.integrante_id === miembro.id);
      if (!pago) return;
      setConfirmBorrar({ miembro, pago });
    } else {
      // Caso especial: la contadora está registrando su PROPIO pago
      if (esCuerdaContador(user) && miembro.id === user.id) {
        setConfirmContadora({ miembro });
        return;
      }
      // Marcar pago de otro → mostrar modal explicativo primero
      setConfirmPagarConComprobante({ miembro });
    }
  }

  function solicitarComprobante(miembro) {
    setConfirmPagarConComprobante(null);
    const input = fileRefs.current[miembro.id];
    if (input) {
      input.click();
    } else {
      alert("Recarga la página e inténtalo de nuevo para adjuntar el comprobante.");
    }
  }

  async function ejecutarPagoContadora(miembro) {
    setProcesando(true);
    try {
      const mesLabel = finMesLabel(mesSeleccionado);
      const nota = `texto:Cuota de ${mesLabel} registrada con cargo a la cuenta corriente de la Contadora/Tesorera del coro. No aplica transferencia.`;
      await finDbPost("fin_pagos", {
        integrante_id: miembro.id,
        mes: mesSeleccionado,
        monto: montoParaMiembro(miembro),
        tipo: "cuota",
        comprobante_url: nota,
      });
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setConfirmContadora(null);
    setProcesando(false);
  }

  async function ejecutarPago(miembro) {
    setProcesando(true);
    try {
      await finDbPost("fin_pagos", {
        integrante_id: miembro.id,
        mes: mesSeleccionado,
        monto: montoParaMiembro(miembro),
        tipo: "cuota",
      });
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setConfirmPagar(null);
    setProcesando(false);
  }

  async function ejecutarBorrarPago(pago) {
    setProcesando(true);
    try {
      await finDbDelete("fin_pagos", pago.id);
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setConfirmBorrar(null);
    setProcesando(false);
  }

  async function subirComprobante(miembro, file) {
    setUploadingId(miembro.id);
    try {
      let pago = pagosMes.find((p) => p.integrante_id === miembro.id);
      if (!pago) {
        // Al adjuntar comprobante se marca el pago automáticamente (un solo paso)
        const creado = await finDbPost("fin_pagos", {
          integrante_id: miembro.id,
          mes: mesSeleccionado,
          monto: montoParaMiembro(miembro),
          tipo: "cuota",
        });
        pago = Array.isArray(creado) ? creado[0] : creado;
      }
      if (!pago || !pago.id) throw new Error("No se pudo registrar el pago.");
      const ext = (file.name.split(".").pop() || "jpg").toLowerCase();
      const path = `comprobantes/${mesSeleccionado}/${miembro.id}_${Date.now()}.${ext}`;
      const url = await finUploadFile("finanzas", path, file);
      await finDbPatch("fin_pagos", pago.id, { comprobante_url: url });
      await reload();
    } catch (e) {
      alert("Error subiendo comprobante: " + e.message);
    }
    setUploadingId(null);
  }

  const pctPago = miembrosActivos.length
    ? Math.round((pagaron.size / miembrosActivos.length) * 100)
    : 0;

  // No mostrar morosos si el plazo aún no ha vencido
  // El plazo de pago vence el día 20 del mes siguiente al mes de la cuota
  const hoy = new Date();
  const [mesAnio, mesMes] = mesSeleccionado.split("-").map(Number);
  const plazoVencimientoTabCuotas = new Date(mesAnio, mesMes, 20); // mesMes sin -1 = mes siguiente (0-based)
  const mesVencido = hoy > plazoVencimientoTabCuotas;

  return (
    <div>

      {/* ══ MODAL: Explicación antes de pedir comprobante ══ */}
      {confirmPagarConComprobante && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.40)", backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ background: "rgba(255,255,255,0.97)", backdropFilter: "saturate(180%) blur(20px)", WebkitBackdropFilter: "saturate(180%) blur(20px)", borderRadius: 22, padding: "28px 24px", maxWidth: 400, width: "90%", boxShadow: "0 24px 72px rgba(0,0,0,0.18), 0 4px 16px rgba(0,0,0,0.08)", border: "1px solid rgba(255,255,255,0.8)" }}>
            <div style={{ fontSize: 32, textAlign: "center", marginBottom: 10 }}>📎</div>
            <div style={{ fontFamily: "var(--font-display)", fontSize: 16, fontWeight: 700, color: "var(--text-primary)", textAlign: "center", marginBottom: 10 }}>
              Registrar pago de cuota
            </div>
            {/* Quién */}
            <div style={{ background: "#f0fdf4", border: "1px solid #bbf7d0", borderRadius: 12, padding: "10px 14px", marginBottom: 14, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <span style={{ fontSize: 13, fontWeight: 700, color: "#14532d" }}>{confirmPagarConComprobante.miembro.nombre}</span>
              <span style={{ fontSize: 13, fontWeight: 700, color: "#15803d" }}>{finFmtCLP(cuotaMes?.valor || 0)} · {finMesLabel(mesSeleccionado)}</span>
            </div>
            {/* Explicación */}
            <div style={{ fontSize: 13, color: "var(--text-secondary)", lineHeight: 1.65, marginBottom: 16 }}>
              Para registrar este pago <strong>debes adjuntar el comprobante de transferencia</strong> que el integrante te envió.
              <div style={{ marginTop: 10, background: "#fefce8", border: "1px solid #fde68a", borderRadius: 10, padding: "10px 13px", fontSize: 12, color: "#78350f", lineHeight: 1.6 }}>
                💡 <strong>¿Por qué?</strong> El comprobante queda guardado como respaldo en caso de cualquier duda futura sobre los pagos del coro. Sin comprobante no se puede registrar el pago.
              </div>
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button
                onClick={() => solicitarComprobante(confirmPagarConComprobante.miembro)}
                style={{ flex: 1, background: "linear-gradient(135deg,#1d6fc7,#1a4d8f)", border: "none", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 700, color: "white", cursor: "pointer" }}
              >📎 Adjuntar comprobante</button>
              <button
                onClick={() => setConfirmPagarConComprobante(null)}
                style={{ flex: 1, background: "white", border: "1.5px solid #e2e8f0", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 600, color: "var(--text-secondary)", cursor: "pointer" }}
              >Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {/* ══ MODAL: Pago propio de la Contadora (sin transferencia) ══ */}
      {confirmContadora && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.40)", backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ background: "rgba(255,255,255,0.97)", backdropFilter: "saturate(180%) blur(20px)", WebkitBackdropFilter: "saturate(180%) blur(20px)", borderRadius: 22, padding: "28px 28px", maxWidth: 380, width: "90%", boxShadow: "0 24px 72px rgba(0,0,0,0.18), 0 4px 16px rgba(0,0,0,0.08)", border: "1px solid rgba(255,255,255,0.8)" }}>
            <div style={{ fontSize: 32, textAlign: "center", marginBottom: 10 }}>🏦</div>
            <div style={{ fontFamily: "var(--font-display)", fontSize: 16, fontWeight: 700, color: "var(--text-primary)", textAlign: "center", marginBottom: 6 }}>
              Registrar tu cuota
            </div>
            <div style={{ fontSize: 13, color: "var(--text-secondary)", textAlign: "center", marginBottom: 14, lineHeight: 1.6 }}>
              Como Contadora/Tesorera, los fondos del coro se guardan en tu cuenta corriente.
            </div>
            <div style={{ background: "#f0f9ff", border: "1px solid #bae6fd", borderRadius: 12, padding: "12px 14px", marginBottom: 18, fontSize: 12.5, color: "#0c4a6e", lineHeight: 1.6 }}>
              📝 Se guardará la siguiente nota como respaldo:<br />
              <span style={{ fontStyle: "italic", marginTop: 6, display: "block", color: "#0369a1" }}>
                "Cuota de {finMesLabel(mesSeleccionado)} registrada con cargo a la cuenta corriente de la Contadora/Tesorera del coro. No aplica transferencia."
              </span>
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button
                onClick={() => ejecutarPagoContadora(confirmContadora.miembro)}
                disabled={procesando}
                style={{ flex: 1, background: "linear-gradient(135deg,#1d6fc7,#1a4d8f)", border: "none", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 700, color: "white", cursor: procesando ? "not-allowed" : "pointer", opacity: procesando ? 0.7 : 1 }}
              >{procesando ? "Registrando..." : "✅ Confirmar"}</button>
              <button
                onClick={() => setConfirmContadora(null)}
                disabled={procesando}
                style={{ flex: 1, background: "white", border: "1.5px solid #e2e8f0", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 600, color: "var(--text-secondary)", cursor: "pointer" }}
              >Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {/* ══ MODAL: Confirmar registro de pago ══ */}
      {confirmPagar && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.40)", backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ background: "rgba(255,255,255,0.97)", backdropFilter: "saturate(180%) blur(20px)", WebkitBackdropFilter: "saturate(180%) blur(20px)", borderRadius: 22, padding: "28px 28px", maxWidth: 380, width: "90%", boxShadow: "0 24px 72px rgba(0,0,0,0.18), 0 4px 16px rgba(0,0,0,0.08)", border: "1px solid rgba(255,255,255,0.8)" }}>
            <div style={{ fontSize: 32, textAlign: "center", marginBottom: 10 }}>✅</div>
            <div style={{ fontFamily: "var(--font-display)", fontSize: 16, fontWeight: 700, color: "var(--text-primary)", textAlign: "center", marginBottom: 6 }}>
              Confirmar pago
            </div>
            <div style={{ fontSize: 13, color: "var(--text-secondary)", textAlign: "center", marginBottom: 18, lineHeight: 1.6 }}>
              ¿Registrar el pago de cuota de <strong>{confirmPagar.miembro.nombre}</strong>?
              <div style={{ marginTop: 10, background: "#f0fdf4", border: "1px solid #bbf7d0", borderRadius: 12, padding: "10px 14px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <span style={{ fontSize: 12, color: "#166534" }}>📅 {mesSeleccionado}</span>
                <span style={{ fontSize: 14, fontWeight: 700, color: "#15803d" }}>{finFmtCLP(cuotaMes?.valor || 0)}</span>
              </div>
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button
                onClick={() => ejecutarPago(confirmPagar.miembro)}
                disabled={procesando}
                style={{ flex: 1, background: "linear-gradient(135deg,#1d6fc7,#1a4d8f)", border: "none", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 700, color: "white", cursor: procesando ? "not-allowed" : "pointer", opacity: procesando ? 0.7 : 1 }}
              >{procesando ? "Registrando..." : "✅ Sí, registrar pago"}</button>
              <button
                onClick={() => setConfirmPagar(null)}
                disabled={procesando}
                style={{ flex: 1, background: "white", border: "1.5px solid #e2e8f0", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 600, color: "var(--text-secondary)", cursor: "pointer" }}
              >Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {/* ══ MODAL: Confirmar eliminación de pago ══ */}
      {confirmBorrar && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.42)", backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ background: "rgba(255,255,255,0.97)", backdropFilter: "saturate(180%) blur(20px)", WebkitBackdropFilter: "saturate(180%) blur(20px)", borderRadius: 22, padding: "28px 28px", maxWidth: 400, width: "90%", boxShadow: "0 24px 72px rgba(0,0,0,0.18), 0 4px 16px rgba(0,0,0,0.08)", border: "1.5px solid #fecaca" }}>
            <div style={{ fontSize: 32, textAlign: "center", marginBottom: 10 }}>⚠️</div>
            <div style={{ fontFamily: "var(--font-display)", fontSize: 16, fontWeight: 700, color: "#dc2626", textAlign: "center", marginBottom: 6 }}>
              ¿Eliminar este pago?
            </div>
            <div style={{ fontSize: 13, color: "var(--text-secondary)", textAlign: "center", marginBottom: 6, lineHeight: 1.6 }}>
              Estás a punto de <strong>borrar el pago registrado</strong> de:
            </div>
            <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 12, padding: "12px 16px", marginBottom: 14 }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: "var(--text-primary)", marginBottom: 4 }}>{confirmBorrar.miembro.nombre}</div>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "var(--text-secondary)" }}>
                <span>📅 {mesSeleccionado}</span>
                <span style={{ fontWeight: 600, color: "#dc2626" }}>{finFmtCLP(confirmBorrar.pago.monto)}</span>
              </div>
              {confirmBorrar.pago.comprobante_url && (
                <div style={{ marginTop: 8, padding: "6px 10px", background: "#fff7ed", border: "1px solid #fed7aa", borderRadius: 10, display: "flex", alignItems: "center", gap: 6 }}>
                  <span style={{ fontSize: 14 }}>{confirmBorrar.pago.comprobante_url.startsWith("texto:") ? "📝" : "📎"}</span>
                  <span style={{ fontSize: 11, color: "#92400e", fontWeight: 600 }}>
                    {confirmBorrar.pago.comprobante_url.startsWith("texto:") ? "Este pago tiene una nota de respaldo. También se perderá." : "Este pago tiene comprobante adjunto. También se perderá."}
                  </span>
                </div>
              )}
            </div>
            <div style={{ fontSize: 12, color: "var(--text-tertiary)", textAlign: "center", marginBottom: 16 }}>
              Esta acción no se puede deshacer.
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button
                onClick={() => setConfirmBorrar(null)}
                disabled={procesando}
                style={{ flex: 1, background: "white", border: "1.5px solid #e2e8f0", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 700, color: "var(--text-secondary)", cursor: "pointer" }}
              >← No, mantener pago</button>
              <button
                onClick={() => ejecutarBorrarPago(confirmBorrar.pago)}
                disabled={procesando}
                style={{ flex: 1, background: "linear-gradient(135deg,#dc2626,#b91c1c)", border: "none", borderRadius: 12, padding: "11px 0", fontSize: 13, fontWeight: 700, color: "white", cursor: procesando ? "not-allowed" : "pointer", opacity: procesando ? 0.7 : 1 }}
              >{procesando ? "Eliminando..." : "🗑 Sí, eliminar pago"}</button>
            </div>
          </div>
        </div>
      )}
      {/* Aviso pago anticipado */}
      {(() => {
        const hoyCheck = new Date();
        const mesActualIso = `${hoyCheck.getFullYear()}-${String(hoyCheck.getMonth() + 1).padStart(2, "0")}`;
        const esPagoAnticipado = mesSeleccionado > mesActualIso;
        if (!esPagoAnticipado) return null;
        return (
          <div style={{ background: "#fffbeb", border: "1.5px solid #fcd34d", borderRadius: 14, padding: "10px 16px", marginBottom: 16, display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ fontSize: 20 }}>🗓️</span>
            <div>
              <div style={{ fontWeight: 700, fontSize: 13, color: "#92400e" }}>Pago anticipado — {finMesLabel(mesSeleccionado)}</div>
              <div style={{ fontSize: 12, color: "#b45309", marginTop: 2 }}>
                Estás registrando el pago del próximo mes (vence el día 5). Disponible a partir del día 20 del mes anterior.
              </div>
            </div>
          </div>
        );
      })()}

      {/* Selector de mes y valor de cuota */}
      <div style={{ display: "flex", gap: 12, flexWrap: "wrap", marginBottom: 20, alignItems: "flex-end" }}>
        <div>
          <div style={{ fontSize: 11, color: C.gray, marginBottom: 4 }}>Mes</div>
          <select
            value={mesSeleccionado}
            onChange={(e) => setMesSeleccionado(e.target.value)}
            style={inputS}
          >
            {mesesDisponibles.map((m) => {
              const hoyChk = new Date();
              const mesActIso = `${hoyChk.getFullYear()}-${String(hoyChk.getMonth() + 1).padStart(2, "0")}`;
              const esAnticipado = m > mesActIso;
              return (
                <option key={m} value={m}>{finMesLabel(m)}{esAnticipado ? " ⚡ anticipado" : ""}</option>
              );
            })}
          </select>
        </div>
        <div>
          <div style={{ fontSize: 11, color: C.gray, marginBottom: 4 }}>
            Valor cuota {cuotaMes ? `(actual: ${finFmtCLP(cuotaMes.valor)})` : "(sin definir)"}
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <input
              type="number"
              placeholder="Ej: 5000"
              value={valorCuota}
              onChange={(e) => setValorCuota(e.target.value)}
              style={{ ...inputS, width: 130 }}
            />
            <FinBtn onClick={guardarValorCuota} disabled={saving}>
              {saving ? "Guardando..." : "Fijar cuota"}
            </FinBtn>
          </div>
        </div>
      </div>

      {/* Stats del mes */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(180px,1fr))", gap: 12, marginBottom: 20 }}>
        <StatCard icon="👥" label="En sistema" value={miembrosActivos.length} color="#3b82f6" />
        <StatCard icon="✅" label="Pagaron" value={pagaron.size} color={C.primary} sub={`${pctPago}%`} />
        <StatCard icon="⚠️" label="Morosos" value={mesVencido ? miembrosActivos.length - pagaron.size : "—"} color="#ef4444" />
        <StatCard icon="💰" label="Recaudado" value={finFmtCLP(totalRecaudado)} color="#2d7dd2" sub={`de ${finFmtCLP(totalEsperado)}`} />
      </div>

      {/* Barra de progreso */}
      <div style={{ marginBottom: 20 }}>
        <div style={{ height: 8, background: C.border, borderRadius: 7, overflow: "hidden" }}>
          <div
            style={{
              height: "100%",
              width: `${pctPago}%`,
              background: `linear-gradient(90deg,${C.primary},${C.primaryDark})`,
              borderRadius: 7,
              transition: "width 0.4s",
            }}
          />
        </div>
        <div style={{ fontSize: 11, color: C.gray, marginTop: 4 }}>
          {pagaron.size} de {miembrosActivos.length} integrantes han pagado en {finMesLabel(mesSeleccionado)}
        </div>
      </div>

      {/* Lista de integrantes */}
      <div style={{ background: "#fff7e6", border: "1px solid #ffd98a", borderRadius: 10, padding: "10px 13px", margin: "0 0 8px", fontSize: 12.5, color: "#7a4d00", display: "flex", gap: 8, alignItems: "flex-start" }}>
        <span style={{ fontSize: 15, flexShrink: 0 }}>📌</span>
        <span>Para registrar un pago es <b>obligatorio adjuntar el comprobante</b> (una imagen) como respaldo. Al marcar a una persona como pagada se te pedirá la imagen del comprobante.</span>
      </div>
      <div style={{ background: "#f0f9ff", border: "1px solid #bae6fd", borderRadius: 10, padding: "10px 13px", margin: "0 0 12px", fontSize: 12.5, color: "#0c4a6e", display: "flex", gap: 8, alignItems: "flex-start" }}>
        <span style={{ fontSize: 15, flexShrink: 0 }}>🎓</span>
        <span><b>Recordatorio:</b> Los <b>Adultos</b> pagan el valor de cuota fijado. Los <b>Estudiantes</b> pagan <b>$3.000</b> fijo. Haz clic en el badge <strong>👤 Adulto</strong> o <strong>🎓 Estudiante</strong> de cada integrante para cambiar su tipo.</span>
      </div>
      {miembrosActivos.length === 0 ? (
        <div style={{ textAlign: "center", padding: "30px 0", color: C.gray, fontSize: 13 }}>
          No hay integrantes en el sistema de cuotas aún. Ve a la pestaña <strong>Participantes</strong> para agregarlos.
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {miembrosActivos.map((m) => {
            const pago = pagosMes.find((p) => p.integrante_id === m.id);
            const pagado = pagaron.has(m.id);
            return (
              <div
                key={m.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 12,
                  padding: "12px 16px",
                  borderRadius: 12,
                  border: `1px solid ${pagado ? C.primary + "40" : C.border}`,
                  background: pagado ? C.primary + "08" : C.white,
                  transition: "all 0.2s",
                }}
              >
                <Avatar nombre={m.nombre} foto_url={m.foto_url} size={36} />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontWeight: 600, color: C.dark, fontSize: 14, display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}>
                    {m.nombre}
                    <button
                      onClick={() => toggleTipoCuotas(m)}
                      disabled={savingTipo === m.id}
                      title="Clic para cambiar tipo"
                      style={{ fontSize: 10, fontWeight: 700, borderRadius: 20, padding: "2px 8px", cursor: "pointer", border: "none",
                        background: miembrosEnCuotas.find((r) => r.integrante_id === m.id)?.es_estudiante ? "#e0f2fe" : "#f1f5f9",
                        color: miembrosEnCuotas.find((r) => r.integrante_id === m.id)?.es_estudiante ? "#0369a1" : "#64748b",
                      }}>
                      {savingTipo === m.id ? "…" : miembrosEnCuotas.find((r) => r.integrante_id === m.id)?.es_estudiante ? "🎓 Estudiante" : "👤 Adulto"}
                    </button>
                  </div>
                  <div style={{ fontSize: 11, color: C.gray }}>{finCuerdaLabel(m.cuerda)} · {finFmtCLP(montoParaMiembro(m))}</div>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    {pago?.comprobante_url ? (
                      pago.comprobante_url.startsWith("texto:") ? (
                        <span
                          title={pago.comprobante_url.replace("texto:", "")}
                          style={{ fontSize: 11, color: "#0369a1", cursor: "help", display: "flex", alignItems: "center", gap: 4 }}
                        >
                          📝 Nota registrada
                        </span>
                      ) : (
                      <a
                        href={pago.comprobante_url}
                        target="_blank"
                        rel="noreferrer"
                        style={{ fontSize: 11, color: C.primary, textDecoration: "none", display: "flex", alignItems: "center", gap: 4 }}
                      >
                        📎 Ver comprobante
                      </a>
                      )
                    ) : (
                      <div>
                        <input
                          type="file"
                          accept="image/*"
                          style={{ display: "none" }}
                          ref={(el) => (fileRefs.current[m.id] = el)}
                          onChange={(e) => e.target.files[0] && subirComprobante(m, e.target.files[0])}
                        />
                        <FinBtn
                          variant="ghost"
                          onClick={() => fileRefs.current[m.id]?.click()}
                          disabled={uploadingId === m.id}
                          style={{ fontSize: 12, padding: "8px 12px" }}
                        >
                          {uploadingId === m.id ? "Subiendo..." : "📎 Comprobante"}
                        </FinBtn>
                      </div>
                    )}
                  </div>
                <button
                  onClick={() => togglePago(m)}
                  style={{
                    width: 32,
                    height: 32,
                    borderRadius: "50%",
                    border: `2px solid ${pagado ? C.primary : C.border}`,
                    background: pagado ? C.primary : "white",
                    cursor: "pointer",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    fontSize: 16,
                    flexShrink: 0,
                    transition: "all 0.2s",
                  }}
                  title={pagado ? "Desmarcar pago" : "Marcar como pagado"}
                >
                  {pagado ? "✓" : ""}
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  TAB: ACTIVIDADES
// ══════════════════════════════════════════════════════════════════════

function TabActividades({ actividades, gastos, members, pagos, reload }) {
  const [showForm, setShowForm] = useState(false);
  // Step 1: choose tipo; Step 2: fill details
  const [tipoModal, setTipoModal] = useState(false); // show tipo selector
  const [form, setForm] = useState({ nombre: "", fecha: "", descripcion: "", tipo_actividad: "general", num_personas: "" });
  const [saving, setSaving] = useState(false);
  const [actSeleccionada, setActSeleccionada] = useState(null);
  const [showPagoExtra, setShowPagoExtra] = useState(false);
  const [pagoExtraForm, setPagoExtraForm] = useState({ integrante_id: "", monto: "", descripcion: "" });
  const fileRef = useRef(null);
  const [uploadingGasto, setUploadingGasto] = useState(false);
  const [gastoForm, setGastoForm] = useState({ descripcion: "", monto: "" });
  // Edit personas modal
  const [editPersonas, setEditPersonas] = useState(false);
  const [draftPersonas, setDraftPersonas] = useState("");
  const [savingPersonas, setSavingPersonas] = useState(false);

  function abrirNuevaActividad() {
    setTipoModal(true);
  }

  function elegirTipo(tipo) {
    setForm({ nombre: "", fecha: "", descripcion: "", tipo_actividad: tipo, num_personas: "" });
    setTipoModal(false);
    setShowForm(true);
  }

  async function crearActividad() {
    if (!form.nombre.trim()) return;
    setSaving(true);
    try {
      const payload = {
        nombre: form.nombre,
        fecha: form.fecha,
        descripcion: form.descripcion,
        tipo_actividad: form.tipo_actividad,
        num_personas: form.tipo_actividad === "asado" && form.num_personas ? parseInt(form.num_personas) : null,
      };
      await finDbPost("fin_actividades", payload);
      setForm({ nombre: "", fecha: "", descripcion: "", tipo_actividad: "general", num_personas: "" });
      setShowForm(false);
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setSaving(false);
  }

  async function guardarPersonas() {
    if (!actSeleccionada) return;
    setSavingPersonas(true);
    try {
      await finDbPatch("fin_actividades", actSeleccionada.id, { num_personas: parseInt(draftPersonas) || null });
      setEditPersonas(false);
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setSavingPersonas(false);
  }

  async function eliminarActividad(id) {
    if (!window.confirm("¿Eliminar esta actividad?")) return;
    try {
      await finDbDelete("fin_actividades", id);
      if (actSeleccionada?.id === id) setActSeleccionada(null);
      await reload();
    } catch (e) { alert("Error: " + e.message); }
  }

  async function subirBoleta(file) {
    if (!actSeleccionada || !gastoForm.descripcion || !gastoForm.monto) {
      alert("Completa descripción y monto antes de subir la boleta.");
      return;
    }
    setUploadingGasto(true);
    try {
      const path = `boletas/${actSeleccionada.id}/${Date.now()}.${file.name.split(".").pop()}`;
      const url = await finUploadFile("finanzas", path, file);
      await finDbPost("fin_gastos", {
        actividad_id: actSeleccionada.id,
        descripcion: gastoForm.descripcion,
        monto: parseFloat(gastoForm.monto),
        boleta_url: url,
      });
      setGastoForm({ descripcion: "", monto: "" });
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setUploadingGasto(false);
  }

  async function agregarGastoSinBoleta() {
    if (!actSeleccionada || !gastoForm.descripcion || !gastoForm.monto) return;
    setSaving(true);
    try {
      await finDbPost("fin_gastos", {
        actividad_id: actSeleccionada.id,
        descripcion: gastoForm.descripcion,
        monto: parseFloat(gastoForm.monto),
      });
      setGastoForm({ descripcion: "", monto: "" });
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setSaving(false);
  }

  async function registrarPagoExtra() {
    if (!pagoExtraForm.integrante_id || !pagoExtraForm.monto) return;
    setSaving(true);
    try {
      await finDbPost("fin_pagos", {
        integrante_id: pagoExtraForm.integrante_id,
        actividad_id: actSeleccionada?.id || null,
        monto: parseFloat(pagoExtraForm.monto),
        descripcion: pagoExtraForm.descripcion,
        tipo: "actividad",
        mes: finCurrentMesIso(),
      });
      setPagoExtraForm({ integrante_id: "", monto: "", descripcion: "" });
      setShowPagoExtra(false);
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setSaving(false);
  }

  const gastosAct = actSeleccionada
    ? gastos.filter((g) => g.actividad_id === actSeleccionada.id)
    : [];
  const totalGastosAct = gastosAct.reduce((s, g) => s + (g.monto || 0), 0);
  const pagosAct = actSeleccionada
    ? pagos.filter((p) => p.actividad_id === actSeleccionada.id)
    : [];
  const totalPagosAct = pagosAct.reduce((s, p) => s + (p.monto || 0), 0);

  // Costo por persona (informativo, no es cobro — muestra en qué se usaron los fondos)
  const actActual = actSeleccionada ? actividades.find(a => a.id === actSeleccionada.id) : null;
  const esAsado = actActual?.tipo_actividad === "asado";
  const numPersonas = actActual?.num_personas || 0;
  const cuotaPromedio = (esAsado && numPersonas > 0) ? Math.round(totalGastosAct / numPersonas) : null;

  return (
    <div style={{ display: "grid", gridTemplateColumns: "280px 1fr", gap: 16, alignItems: "start" }}>

      {/* ── Modal selector de tipo ── */}
      {tipoModal && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.40)", backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ background: "rgba(255,255,255,0.97)", backdropFilter: "saturate(180%) blur(20px)", WebkitBackdropFilter: "saturate(180%) blur(20px)", borderRadius: 22, padding: "28px 30px", maxWidth: 420, width: "90%", boxShadow: "0 24px 72px rgba(0,0,0,0.18), 0 4px 16px rgba(0,0,0,0.08)", border: "1px solid rgba(255,255,255,0.8)" }}>
            <div style={{ fontFamily: "var(--font-display)", fontSize: 17, fontWeight: 700, color: C.dark, marginBottom: 6 }}>
              ¿Qué tipo de actividad es?
            </div>
            <div style={{ fontSize: 13, color: C.gray, marginBottom: 20 }}>
              El tipo determina cómo se calculan los costos compartidos.
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              <button
                onClick={() => elegirTipo("general")}
                style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 18px", border: `1.5px solid ${C.border}`, borderRadius: 14, background: "white", cursor: "pointer", textAlign: "left", transition: "border-color 0.15s" }}
                onMouseEnter={e => e.currentTarget.style.borderColor = C.primary}
                onMouseLeave={e => e.currentTarget.style.borderColor = C.border}
              >
                <span style={{ fontSize: 28 }}>🎉</span>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 14, color: C.dark }}>Actividad General</div>
                  <div style={{ fontSize: 12, color: C.gray }}>Cumpleaños, retiro, ensayo especial, etc.</div>
                </div>
              </button>
              <button
                onClick={() => elegirTipo("asado")}
                style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 18px", border: `1.5px solid ${C.border}`, borderRadius: 14, background: "white", cursor: "pointer", textAlign: "left", transition: "border-color 0.15s" }}
                onMouseEnter={e => e.currentTarget.style.borderColor = C.primary}
                onMouseLeave={e => e.currentTarget.style.borderColor = C.border}
              >
                <span style={{ fontSize: 28 }}>🔥</span>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 14, color: C.dark }}>Asado / Evento con cuota</div>
                  <div style={{ fontSize: 12, color: C.gray }}>Requiere cantidad de personas para mostrar el costo por persona (transparencia de gastos).</div>
                </div>
              </button>
            </div>
            <button onClick={() => setTipoModal(false)} style={{ marginTop: 16, background: "none", border: "none", color: C.gray, fontSize: 12, cursor: "pointer" }}>
              Cancelar
            </button>
          </div>
        </div>
      )}

      {/* Listado de actividades */}
      <div>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 600, color: C.dark }}>Actividades</span>
          <FinBtn onClick={abrirNuevaActividad} style={{ fontSize: 12, padding: "5px 10px" }}>
            + Nueva
          </FinBtn>
        </div>
        {showForm && (
          <FinCard style={{ marginBottom: 10, padding: 14 }}>
            {/* Tipo badge */}
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10, padding: "6px 10px", background: form.tipo_actividad === "asado" ? "#fff7ed" : "#f0fdf4", borderRadius: 10, border: `1px solid ${form.tipo_actividad === "asado" ? "#fed7aa" : "#bbf7d0"}` }}>
              <span>{form.tipo_actividad === "asado" ? "🔥" : "🎉"}</span>
              <span style={{ fontSize: 12, fontWeight: 600, color: form.tipo_actividad === "asado" ? "#c2410c" : C.primary }}>
                {form.tipo_actividad === "asado" ? "Asado / Evento con cuota" : "Actividad General"}
              </span>
              <button onClick={() => { setShowForm(false); setTipoModal(true); }} style={{ marginLeft: "auto", background: "none", border: "none", fontSize: 11, color: C.gray, cursor: "pointer" }}>cambiar</button>
            </div>
            <input
              placeholder="Nombre de la actividad *"
              value={form.nombre}
              onChange={(e) => setForm({ ...form, nombre: e.target.value })}
              style={{ ...inputS, marginBottom: 8 }}
            />
            <input
              type="date"
              value={form.fecha}
              onChange={(e) => setForm({ ...form, fecha: e.target.value })}
              style={{ ...inputS, marginBottom: 8 }}
            />
            <textarea
              placeholder="Descripción (opcional)"
              value={form.descripcion}
              onChange={(e) => setForm({ ...form, descripcion: e.target.value })}
              rows={2}
              style={{ ...inputS, resize: "vertical", marginBottom: 8 }}
            />
            {form.tipo_actividad === "asado" && (
              <input
                type="number"
                placeholder="Cantidad de personas *"
                value={form.num_personas}
                onChange={(e) => setForm({ ...form, num_personas: e.target.value })}
                style={{ ...inputS, marginBottom: 8 }}
                min={1}
              />
            )}
            <FinBtn onClick={crearActividad} disabled={saving}>
              {saving ? "Guardando..." : "Crear actividad"}
            </FinBtn>
          </FinCard>
        )}
        <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
          {actividades.length === 0 && (
            <div style={{ fontSize: 12, color: C.gray, padding: "12px 0" }}>Sin actividades registradas.</div>
          )}
          {actividades.map((a) => {
            const gastosA = gastos.filter((g) => g.actividad_id === a.id).length;
            const selected = actSeleccionada?.id === a.id;
            return (
              <div
                key={a.id}
                onClick={() => setActSeleccionada(selected ? null : a)}
                style={{ padding: "10px 12px", borderRadius: 12, border: `1px solid ${selected ? C.primary : C.border}`, background: selected ? C.primary + "10" : C.white, cursor: "pointer", transition: "all 0.15s" }}
              >
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 2 }}>
                  <span style={{ fontSize: 13 }}>{a.tipo_actividad === "asado" ? "🔥" : "🎉"}</span>
                  <div style={{ fontWeight: 600, fontSize: 13, color: C.dark }}>{a.nombre}</div>
                </div>
                {a.fecha && <div style={{ fontSize: 11, color: C.gray }}>{a.fecha}</div>}
                <div style={{ fontSize: 11, color: C.gray, marginTop: 2 }}>
                  {gastosA} boleta{gastosA !== 1 ? "s" : ""}
                  {a.tipo_actividad === "asado" && a.num_personas ? ` · ${a.num_personas} personas` : ""}
                </div>
                <button
                  onClick={(e) => { e.stopPropagation(); eliminarActividad(a.id); }}
                  style={{ fontSize: 10, color: "#ef4444", background: "none", border: "none", cursor: "pointer", marginTop: 4 }}
                >
                  🗑 Eliminar
                </button>
              </div>
            );
          })}
        </div>
      </div>

      {/* Detalle de actividad seleccionada */}
      {actSeleccionada ? (
        <div>
          <FinCard style={{ marginBottom: 14 }}>
            <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 4 }}>
              <div>
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 2 }}>
                  <span>{esAsado ? "🔥" : "🎉"}</span>
                  <div style={{ fontWeight: 700, fontSize: 16, color: C.dark }}>{actSeleccionada.nombre}</div>
                </div>
                {actSeleccionada.descripcion && (
                  <div style={{ fontSize: 13, color: C.gray, marginBottom: 8 }}>{actSeleccionada.descripcion}</div>
                )}
              </div>
            </div>
            <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
              <StatCard icon="💸" label="Total gastos" value={finFmtCLP(totalGastosAct)} color="#ef4444" />
              <StatCard icon="💵" label="Ingresos actividad" value={finFmtCLP(totalPagosAct)} color={C.primary} />
              {esAsado && (
                <div style={{ flex: 1, minWidth: 140 }}>
                  <div style={{ background: "#fff7ed", border: "1px solid #fed7aa", borderRadius: 14, padding: "10px 14px" }}>
                    <div style={{ fontSize: 11, color: "#c2410c", fontWeight: 600, marginBottom: 4 }}>🔥 Costo por persona (referencial)</div>
                    <div style={{ fontSize: 20, fontWeight: 800, color: "#c2410c" }}>
                      {cuotaPromedio !== null ? finFmtCLP(cuotaPromedio) : "—"}
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 6 }}>
                      <span style={{ fontSize: 12, color: C.gray }}>
                        {numPersonas > 0 ? `${numPersonas} asistentes` : "Sin asistentes definidos"}
                      </span>
                      <button
                        onClick={() => { setDraftPersonas(String(numPersonas || "")); setEditPersonas(true); }}
                        style={{ background: "none", border: "none", fontSize: 11, color: C.primary, cursor: "pointer", padding: "0 4px" }}
                      >✏️ editar</button>
                    </div>
                    <div style={{ marginTop: 8, fontSize: 10, color: "#92400e", lineHeight: 1.5, borderTop: "1px solid #fed7aa", paddingTop: 6 }}>
                      Dato informativo: muestra cuánto costó la actividad por persona, financiada con los fondos de la cuota mensual.
                    </div>
                  </div>
                </div>
              )}
            </div>
            {/* Si no es asado pero queremos permitir ver tipo */}
            {!esAsado && (
              <div style={{ marginTop: 8, fontSize: 11, color: C.gray }}>Tipo: Actividad general</div>
            )}
          </FinCard>

          {/* Modal editar personas */}
          {editPersonas && (
            <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.38)", backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <div style={{ background: "rgba(255,255,255,0.97)", backdropFilter: "saturate(180%) blur(20px)", WebkitBackdropFilter: "saturate(180%) blur(20px)", borderRadius: 22, padding: "22px 24px", maxWidth: 340, width: "90%", boxShadow: "0 24px 72px rgba(0,0,0,0.16), 0 4px 16px rgba(0,0,0,0.07)" }}>
                <div style={{ fontWeight: 700, fontSize: 15, color: C.dark, marginBottom: 12 }}>🔥 Cantidad de personas</div>
                <input
                  type="number"
                  value={draftPersonas}
                  onChange={e => setDraftPersonas(e.target.value)}
                  placeholder="Ej: 24"
                  min={1}
                  style={{ ...inputS, marginBottom: 14 }}
                />
                <div style={{ display: "flex", gap: 8 }}>
                  <FinBtn onClick={guardarPersonas} disabled={savingPersonas}>{savingPersonas ? "Guardando..." : "Guardar"}</FinBtn>
                  <FinBtn variant="ghost" onClick={() => setEditPersonas(false)}>Cancelar</FinBtn>
                </div>
              </div>
            </div>
          )}

          {/* Registrar gasto / boleta */}
          <FinCard style={{ marginBottom: 14 }}>
            <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 12, color: C.dark }}>
              📋 Registrar gasto
            </div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 8 }}>
              <input
                placeholder="Descripción del gasto *"
                value={gastoForm.descripcion}
                onChange={(e) => setGastoForm({ ...gastoForm, descripcion: e.target.value })}
                style={{ ...inputS, flex: 2, minWidth: 160 }}
              />
              <input
                type="number"
                placeholder="Monto *"
                value={gastoForm.monto}
                onChange={(e) => setGastoForm({ ...gastoForm, monto: e.target.value })}
                style={{ ...inputS, flex: 1, minWidth: 100 }}
              />
            </div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              <input
                type="file"
                accept="image/*,application/pdf"
                ref={fileRef}
                style={{ display: "none" }}
                onChange={(e) => e.target.files[0] && subirBoleta(e.target.files[0])}
              />
              <FinBtn onClick={() => fileRef.current?.click()} disabled={uploadingGasto}>
                {uploadingGasto ? "Subiendo..." : "📎 Con boleta"}
              </FinBtn>
              <FinBtn variant="ghost" onClick={agregarGastoSinBoleta} disabled={saving}>
                Sin boleta
              </FinBtn>
            </div>
          </FinCard>

          {/* Lista de gastos */}
          <FinCard style={{ marginBottom: 14 }}>
            <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 10, color: C.dark }}>
              🧾 Boletas / Gastos ({gastosAct.length})
            </div>
            {gastosAct.length === 0 ? (
              <div style={{ fontSize: 12, color: C.gray }}>Sin gastos registrados.</div>
            ) : (
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {gastosAct.map((g) => (
                  <div key={g.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 12px", background: C.bg, borderRadius: 8 }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 13, fontWeight: 500, color: C.dark }}>{g.descripcion}</div>
                      <div style={{ fontSize: 11, color: C.gray }}>{g.created_at?.split("T")[0]}</div>
                    </div>
                    <div style={{ fontWeight: 700, color: "#ef4444", fontSize: 13 }}>{finFmtCLP(g.monto)}</div>
                    {g.boleta_url && (
                      <a href={g.boleta_url} target="_blank" rel="noreferrer" style={{ fontSize: 18 }} title="Ver boleta">📎</a>
                    )}
                    <button
                      onClick={async () => { await finDbDelete("fin_gastos", g.id); reload(); }}
                      style={{ background: "none", border: "none", cursor: "pointer", color: "#ef4444", fontSize: 14 }}
                    >🗑</button>
                  </div>
                ))}
              </div>
            )}
          </FinCard>

          {/* Pagos recibidos en actividad */}
          <FinCard>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
              <div style={{ fontWeight: 600, fontSize: 14, color: C.dark }}>
                💵 Pagos recibidos en esta actividad
              </div>
              <FinBtn style={{ fontSize: 12, padding: "5px 10px" }} onClick={() => setShowPagoExtra(!showPagoExtra)}>
                + Agregar
              </FinBtn>
            </div>
            {showPagoExtra && (
              <div style={{ marginBottom: 12, padding: 12, background: C.bg, borderRadius: 8 }}>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 8 }}>
                  <select
                    value={pagoExtraForm.integrante_id}
                    onChange={(e) => setPagoExtraForm({ ...pagoExtraForm, integrante_id: e.target.value })}
                    style={{ ...inputS, flex: 2 }}
                  >
                    <option value="">Seleccionar integrante</option>
                    {members.map((m) => (
                      <option key={m.id} value={m.id}>{m.nombre}</option>
                    ))}
                  </select>
                  <input
                    type="number"
                    placeholder="Monto"
                    value={pagoExtraForm.monto}
                    onChange={(e) => setPagoExtraForm({ ...pagoExtraForm, monto: e.target.value })}
                    style={{ ...inputS, flex: 1 }}
                  />
                </div>
                <input
                  placeholder="Descripción (opcional)"
                  value={pagoExtraForm.descripcion}
                  onChange={(e) => setPagoExtraForm({ ...pagoExtraForm, descripcion: e.target.value })}
                  style={{ ...inputS, marginBottom: 8 }}
                />
                <FinBtn onClick={registrarPagoExtra} disabled={saving}>
                  {saving ? "Guardando..." : "Registrar pago"}
                </FinBtn>
              </div>
            )}
            {pagosAct.length === 0 ? (
              <div style={{ fontSize: 12, color: C.gray }}>Sin pagos registrados.</div>
            ) : (
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {pagosAct.map((p) => {
                  const m = members.find((x) => x.id === p.integrante_id);
                  return (
                    <div key={p.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 12px", background: C.bg, borderRadius: 8 }}>
                      <Avatar nombre={m?.nombre || "?"} foto_url={m?.foto_url} size={28} />
                      <div style={{ flex: 1, fontSize: 13, color: C.dark }}>{m?.nombre || "Desconocido"}</div>
                      <div style={{ fontWeight: 700, color: C.primary, fontSize: 13 }}>{finFmtCLP(p.monto)}</div>
                      {p.comprobante_url && (
                        p.comprobante_url.startsWith("texto:") ? (
                          <span title={p.comprobante_url.replace("texto:", "")} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 12, color: "#0369a1", background: "#e0f2fe", padding: "3px 9px", borderRadius: 20, fontWeight: 600, cursor: "help" }}>
                            📝 Nota
                          </span>
                        ) : (
                        <a href={p.comprobante_url} target="_blank" rel="noreferrer" title="Ver comprobante de pago"
                          style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 12, color: C.primary, textDecoration: "none", background: C.primary + "12", padding: "3px 9px", borderRadius: 20, fontWeight: 600 }}>
                          📎 Comprobante
                        </a>
                        )
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </FinCard>
        </div>
      ) : (
        <div style={{ padding: "40px 20px", textAlign: "center", color: C.gray, fontSize: 13 }}>
          Selecciona una actividad para ver sus detalles
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  TAB: RESUMEN FINANCIERO
// ══════════════════════════════════════════════════════════════════════

function TabResumen({ cuotas, pagos, gastos, actividades }) {
  // Totales globales
  const totalIngresado = pagos.reduce((s, p) => s + (p.monto || 0), 0);
  const totalGastado = gastos.reduce((s, g) => s + (g.monto || 0), 0);
  const saldo = totalIngresado - totalGastado;

  // Por mes
  const mesesConDatos = [...new Set(pagos.map((p) => p.mes))].sort().reverse();

  return (
    <div>
      {/* Resumen global */}
      <div
        style={{
          background: `linear-gradient(135deg,${C.primaryDark},${C.primary})`,
          borderRadius: 16,
          padding: "24px 28px",
          marginBottom: 20,
          color: "white",
        }}
      >
        <div style={{ fontSize: 13, opacity: 0.85, marginBottom: 4 }}>Saldo disponible</div>
        <div
          style={{
            fontSize: 36,
            fontWeight: 800,
            fontFamily: "var(--font-display)",
            marginBottom: 16,
          }}
        >
          {finFmtCLP(saldo)}
        </div>
        <div style={{ display: "flex", gap: 24, flexWrap: "wrap" }}>
          <div>
            <div style={{ fontSize: 11, opacity: 0.75 }}>Total ingresado</div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>{finFmtCLP(totalIngresado)}</div>
          </div>
          <div>
            <div style={{ fontSize: 11, opacity: 0.75 }}>Total gastado</div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>{finFmtCLP(totalGastado)}</div>
          </div>
        </div>
      </div>

      {/* Por mes */}
      <div style={{ fontWeight: 600, fontSize: 14, color: C.dark, marginBottom: 10 }}>
        Detalle por mes
      </div>
      {mesesConDatos.length === 0 ? (
        <div style={{ fontSize: 13, color: C.gray }}>Sin movimientos registrados.</div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {mesesConDatos.map((mes) => {
            const ingresosMes = pagos.filter((p) => p.mes === mes).reduce((s, p) => s + (p.monto || 0), 0);
            const cuota = cuotas.find((c) => c.mes === mes);
            const pagadosMes = pagos.filter((p) => p.mes === mes && p.tipo === "cuota").length;
            return (
              <FinCard key={mes} style={{ padding: "12px 16px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 14, color: C.dark }}>{finMesLabel(mes)}</div>
                    <div style={{ fontSize: 11, color: C.gray }}>
                      {pagadosMes} pago{pagadosMes !== 1 ? "s" : ""} de cuota
                      {cuota ? ` · ${finFmtCLP(cuota.valor)} c/u` : ""}
                    </div>
                  </div>
                  <div style={{ fontWeight: 700, color: C.primary, fontSize: 15 }}>
                    {finFmtCLP(ingresosMes)}
                  </div>
                </div>
              </FinCard>
            );
          })}
        </div>
      )}

      {/* Por actividad */}
      {actividades.length > 0 && (
        <>
          <div style={{ fontWeight: 600, fontSize: 14, color: C.dark, margin: "20px 0 10px" }}>
            Gastos por actividad
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {actividades.map((a) => {
              const gastosA = gastos.filter((g) => g.actividad_id === a.id);
              const totalA = gastosA.reduce((s, g) => s + (g.monto || 0), 0);
              if (totalA === 0) return null;
              return (
                <FinCard key={a.id} style={{ padding: "12px 16px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: 14, color: C.dark }}>{a.nombre}</div>
                      <div style={{ fontSize: 11, color: C.gray }}>{gastosA.length} gasto(s)</div>
                    </div>
                    <div style={{ fontWeight: 700, color: "#ef4444", fontSize: 15 }}>
                      {finFmtCLP(totalA)}
                    </div>
                  </div>
                </FinCard>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  TAB: REPORTE DE MOROSOS
// ══════════════════════════════════════════════════════════════════════

function TabReporte({ members, cuotas, pagos, miembrosEnCuotas }) {
  const [mesReporte, setMesReporte] = useState("2026-06");

  const mesesDisponibles = Array.from({ length: 55 }, (_, i) => {
    const d = new Date(2026, 5 + i); // Junio 2026 → Diciembre 2030
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
  }).reverse();

  const miembrosIds = new Set(miembrosEnCuotas.map((m) => m.integrante_id));
  const miembrosActivos = members.filter((m) => miembrosIds.has(m.id));
  const pagosMes = pagos.filter((p) => p.mes === mesReporte);
  const pagaron = new Set(pagosMes.map((p) => p.integrante_id));
  const cuotaMes = cuotas.find((c) => c.mes === mesReporte);

  const alDia = miembrosActivos.filter((m) => pagaron.has(m.id));
  const morosos = miembrosActivos.filter((m) => !pagaron.has(m.id));
  const hoyR = new Date();
  const [rAnio, rMes] = mesReporte.split("-").map(Number);
  // Moroso solo si ya venció el plazo: día 20 del mes siguiente al mes de la cuota
  const plazoVencimientoR = new Date(rAnio, rMes, 20); // rMes sin -1 = mes siguiente (0-based)
  const mesVencidoR = hoyR > plazoVencimientoR;

  function exportCSV() {
    const rows = [
      ["Nombre", "Estado", "Mes", "Valor cuota"],
      ...alDia.map((m) => [m.nombre, "PAGADO", finMesLabel(mesReporte), cuotaMes?.valor || ""]),
      ...morosos.map((m) => [m.nombre, "MOROSO", finMesLabel(mesReporte), cuotaMes?.valor || ""]),
    ];
    const csv = rows.map((r) => r.join(",")).join("\n");
    const a = document.createElement("a");
    a.href = "data:text/csv;charset=utf-8," + encodeURIComponent(csv);
    a.download = `reporte_cuotas_${mesReporte}.csv`;
    a.click();
  }

  return (
    <div>
      <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 20, flexWrap: "wrap" }}>
        <select value={mesReporte} onChange={(e) => setMesReporte(e.target.value)} style={inputS}>
          {mesesDisponibles.map((m) => (
            <option key={m} value={m}>{finMesLabel(m)}</option>
          ))}
        </select>
        <FinBtn variant="ghost" onClick={exportCSV}>
          📥 Exportar CSV
        </FinBtn>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
        {/* Al día */}
        <FinCard>
          <div style={{ fontWeight: 700, color: C.primary, fontSize: 14, marginBottom: 10, display: "flex", alignItems: "center", gap: 6 }}>
            ✅ Al día ({alDia.length})
          </div>
          {alDia.length === 0 ? (
            <div style={{ fontSize: 12, color: C.gray }}>Ninguno ha pagado aún.</div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {alDia.map((m) => {
                const pago = pagosMes.find((p) => p.integrante_id === m.id);
                return (
                  <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <Avatar nombre={m.nombre} foto_url={m.foto_url} size={28} color={C.primary} />
                    <div style={{ flex: 1, fontSize: 13 }}>{m.nombre}</div>
                    {pago?.comprobante_url && (
                      pago.comprobante_url.startsWith("texto:") ? (
                        <span title={pago.comprobante_url.replace("texto:", "")} style={{ cursor: "help" }}>📝</span>
                      ) : (
                      <a href={pago.comprobante_url} target="_blank" rel="noreferrer" title="Ver comprobante">📎</a>
                      )
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </FinCard>

        {/* Morosos */}
        <FinCard>
          <div style={{ fontWeight: 700, color: "#ef4444", fontSize: 14, marginBottom: 10, display: "flex", alignItems: "center", gap: 6 }}>
            ⚠️ Morosos ({mesVencidoR ? morosos.length : "—"})
          </div>
          {!mesVencidoR ? (
            <div style={{ fontSize: 12, color: C.gray }}>El plazo de pago aún no ha vencido.</div>
          ) : morosos.length === 0 ? (
            <div style={{ fontSize: 12, color: C.gray }}>¡Todos han pagado! 🎉</div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {morosos.map((m) => (
                <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <Avatar nombre={m.nombre} foto_url={m.foto_url} size={28} color="#ef4444" />
                  <div style={{ flex: 1, fontSize: 13 }}>{m.nombre}</div>
                </div>
              ))}
            </div>
          )}
        </FinCard>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  TAB: PARTICIPANTES EN SISTEMA DE CUOTAS
// ══════════════════════════════════════════════════════════════════════

function TabParticipantes({ members, miembrosEnCuotas, reload }) {
  const [saving, setSaving] = useState(null);
  const [savingTipo, setSavingTipo] = useState(null);

  const enSistema = new Set(miembrosEnCuotas.map((m) => m.integrante_id));

  async function toggleMiembro(miembro) {
    setSaving(miembro.id);
    try {
      if (enSistema.has(miembro.id)) {
        const reg = miembrosEnCuotas.find((m) => m.integrante_id === miembro.id);
        await finDbDelete("fin_miembros_cuotas", reg.id);
      } else {
        await finDbPost("fin_miembros_cuotas", { integrante_id: miembro.id, es_estudiante: false });
      }
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setSaving(null);
  }

  async function toggleTipo(miembro) {
    const reg = miembrosEnCuotas.find((m) => m.integrante_id === miembro.id);
    if (!reg) return;
    setSavingTipo(miembro.id);
    try {
      await finDbPatch("fin_miembros_cuotas", reg.id, { es_estudiante: !reg.es_estudiante });
      await reload();
    } catch (e) { alert("Error: " + e.message); }
    setSavingTipo(null);
  }

  const activos = members.filter((m) => enSistema.has(m.id));
  const noActivos = members.filter((m) => !enSistema.has(m.id));

  return (
    <div>
      <div style={{ fontSize: 13, color: C.gray, marginBottom: 16 }}>
        Selecciona los integrantes que participan en el sistema de cuotas mensuales. Puedes agregar o quitar en cualquier momento.
      </div>

      {/* En sistema */}
      <div style={{ fontWeight: 600, fontSize: 14, color: C.dark, marginBottom: 8 }}>
        ✅ En sistema de cuotas ({activos.length})
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 20 }}>
        {activos.length === 0 && (
          <div style={{ fontSize: 12, color: C.gray }}>Ningún integrante en el sistema aún.</div>
        )}
        {activos.map((m) => {
          const reg = miembrosEnCuotas.find((r) => r.integrante_id === m.id);
          const esEst = reg?.es_estudiante;
          return (
          <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 14px", background: C.primary + "08", border: `1px solid ${C.primary}30`, borderRadius: 10 }}>
            <Avatar nombre={m.nombre} foto_url={m.foto_url} size={32} />
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: C.dark }}>{m.nombre}</div>
              <div style={{ fontSize: 11, color: C.gray }}>{finCuerdaLabel(m.cuerda)}</div>
            </div>
            <button
              onClick={() => toggleTipo(m)}
              disabled={savingTipo === m.id}
              title={esEst ? "Cambiar a Adulto" : "Cambiar a Estudiante"}
              style={{ fontSize: 11, padding: "4px 10px", borderRadius: 20, border: `1px solid ${esEst ? "#0369a1" : "#94a3b8"}`, background: esEst ? "#e0f2fe" : "#f1f5f9", color: esEst ? "#0369a1" : "#64748b", cursor: "pointer", fontWeight: 600, whiteSpace: "nowrap" }}>
              {savingTipo === m.id ? "…" : esEst ? "🎓 Estudiante" : "👤 Adulto"}
            </button>
            <FinBtn variant="ghost" onClick={() => toggleMiembro(m)} disabled={saving === m.id} style={{ fontSize: 11, padding: "5px 10px" }}>
              {saving === m.id ? "..." : "Quitar"}
            </FinBtn>
          </div>
        );
        })}
      </div>

      {/* No en sistema */}
      <div style={{ fontWeight: 600, fontSize: 14, color: C.dark, marginBottom: 8 }}>
        Otros integrantes ({noActivos.length})
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        {noActivos.length === 0 && (
          <div style={{ fontSize: 12, color: C.gray }}>Todos los integrantes ya están en el sistema.</div>
        )}
        {noActivos.map((m) => (
          <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 14px", background: C.white, border: `1px solid ${C.border}`, borderRadius: 10 }}>
            <Avatar nombre={m.nombre} foto_url={m.foto_url} size={32} color={C.gray} />
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: C.dark }}>{m.nombre}</div>
              <div style={{ fontSize: 11, color: C.gray }}>{finCuerdaLabel(m.cuerda)}</div>
            </div>
            <FinBtn onClick={() => toggleMiembro(m)} disabled={saving === m.id} style={{ fontSize: 11, padding: "5px 10px" }}>
              {saving === m.id ? "..." : "+ Incluir"}
            </FinBtn>
          </div>
        ))}
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  MÓDULO PRINCIPAL — solo Admin y Contadora
// ══════════════════════════════════════════════════════════════════════

const inputS = {
  padding: "8px 10px",
  borderRadius: 10,
  border: `1px solid #e2e8f0`,
  fontSize: 13,
  outline: "none",
  width: "100%",
  boxSizing: "border-box",
  background: "white",
};

export function ModuloFinanzas({ user, members }) {
  const isAdmin = esCuerdaAdmin(user);
  const isContadora = esCuerdaContador(user);
  const tieneAcceso = isAdmin || isContadora;

  const { cuotas, pagos, actividades, gastos, miembrosEnCuotas, loading, reload } =
    useFinanzasData();

  const [tab, setTab] = useState("cuotas");

  const totalIngresado = pagos.reduce((s, p) => s + (p.monto || 0), 0);
  const totalGastado = gastos.reduce((s, g) => s + (g.monto || 0), 0);
  const saldo = totalIngresado - totalGastado;

  const TABS = [
    { id: "cuotas", label: "💰 Cuotas Mensuales" },
    { id: "actividades", label: "🎵 Actividades" },
    { id: "reporte", label: "📊 Reporte" },
    { id: "participantes", label: "👥 Participantes" },
    { id: "resumen", label: "📈 Resumen" },
  ];

  if (!tieneAcceso) {
    return (
      <div style={{ padding: 40, textAlign: "center", color: C.gray }}>
        <div style={{ fontSize: 40, marginBottom: 12 }}>🔒</div>
        <div style={{ fontWeight: 600, fontSize: 16 }}>Acceso restringido</div>
        <div style={{ fontSize: 13, marginTop: 6 }}>
          Solo el Administrador y el/la Contador/a pueden acceder a este módulo.
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1000 }}>
      {/* Header */}
      <div
        style={{
          background: `linear-gradient(135deg,${C.primaryDark},${C.primary})`,
          borderRadius: 16,
          padding: "20px 24px",
          marginBottom: 20,
          display: "flex",
          alignItems: "center",
          gap: 16,
          flexWrap: "wrap",
        }}
      >
        <div
          style={{
            width: 48,
            height: 48,
            background: "rgba(255,255,255,0.2)",
            borderRadius: 14,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 24,
          }}
        >
          💼
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ fontFamily: "var(--font-display)", fontSize: 18, fontWeight: 700, color: "white" }}>
            Finanzas del Coro
          </div>
          <div style={{ fontSize: 12, color: "rgba(255,255,255,0.8)" }}>
            Panel de gestión financiera · {user?.nombre}
          </div>
        </div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
          {[
            { label: "Saldo disponible", val: finFmtCLP(saldo) },
            { label: "Total gastado", val: finFmtCLP(totalGastado) },
          ].map((s, i) => (
            <div
              key={i}
              style={{
                background: "rgba(255,255,255,0.2)",
                borderRadius: 12,
                padding: "8px 14px",
                textAlign: "center",
              }}
            >
              <div style={{ fontSize: 14, fontWeight: 700, color: "white" }}>{s.val}</div>
              <div style={{ fontSize: 10, color: "rgba(255,255,255,0.8)", marginTop: 2 }}>{s.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 16, paddingBottom: 4 }}>
        {TABS.map((t) => (
          <TabBtn key={t.id} label={t.label} active={tab === t.id} onClick={() => setTab(t.id)} />
        ))}
      </div>

      {/* Contenido */}
      <FinCard>
        {loading ? (
          <FinSpinner />
        ) : (
          <>
            {tab === "cuotas" && (
              <TabCuotas
                members={members}
                cuotas={cuotas}
                pagos={pagos}
                miembrosEnCuotas={miembrosEnCuotas}
                reload={reload}
                user={user}
              />
            )}
            {tab === "actividades" && (
              <TabActividades
                actividades={actividades}
                gastos={gastos}
                members={members}
                pagos={pagos}
                reload={reload}
              />
            )}
            {tab === "reporte" && (
              <TabReporte
                members={members}
                cuotas={cuotas}
                pagos={pagos}
                miembrosEnCuotas={miembrosEnCuotas}
              />
            )}
            {tab === "participantes" && (
              <TabParticipantes
                members={members}
                miembrosEnCuotas={miembrosEnCuotas}
                reload={reload}
              />
            )}
            {tab === "resumen" && (
              <TabResumen
                cuotas={cuotas}
                pagos={pagos}
                gastos={gastos}
                actividades={actividades}
              />
            )}
          </>
        )}
      </FinCard>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  SECCIÓN PÚBLICA: INFORMACIÓN DE GASTOS (visible para todos)
// ══════════════════════════════════════════════════════════════════════

// ══════════════════════════════════════════════════════════════════════
//  PANEL DE VISITAS (Admin)
// ══════════════════════════════════════════════════════════════════════
function AdminVisitas() {
  const [visitas, setVisitas] = useState([]);
  const [online, setOnline] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filtro, setFiltro] = useState("todo");
  const [busqueda, setBusqueda] = useState("");

  useEffect(() => {
    cargar();
    cargarOnline();
    const iv = setInterval(cargarOnline, 20000); // refrescar online cada 20s
    return () => clearInterval(iv);
  }, []);

  async function cargar() {
    setLoading(true);
    try {
      const res = await fetch(
        `${SUPABASE_URL}/rest/v1/visitas_sitio?select=*&order=created_at.desc&limit=500`,
        { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${_authToken || SUPABASE_KEY}` } }
      );
      const data = await res.json();
      setVisitas(Array.isArray(data) ? data : []);
    } catch (e) { setVisitas([]); }
    setLoading(false);
  }

  async function cargarOnline() {
    try {
      // Considerar online: último ping hace menos de 60 segundos
      const umbral = new Date(Date.now() - 60000).toISOString();
      const res = await fetch(
        `${SUPABASE_URL}/rest/v1/presencia_online?select=*&ultimo_ping=gte.${umbral}&order=nombre.asc`,
        { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${_authToken || SUPABASE_KEY}` } }
      );
      const data = await res.json();
      setOnline(Array.isArray(data) ? data : []);
    } catch (e) { /* silencioso */ }
  }

  // Agrupar por integrante
  const porIntegrante = visitas.reduce((acc, v) => {
    const key = v.email || v.nombre;
    if (!acc[key]) acc[key] = { nombre: v.nombre, email: v.email, cuerda: v.cuerda, visitas: [] };
    acc[key].visitas.push(v);
    return acc;
  }, {});

  const ranking = Object.values(porIntegrante)
    .map(p => ({ ...p, total: p.visitas.length, ultima: p.visitas[0]?.created_at }))
    .sort((a, b) => b.total - a.total);

  // Estadísticas
  const hoy = new Date(); hoy.setHours(0,0,0,0);
  const hace7 = new Date(hoy); hace7.setDate(hace7.getDate() - 7);
  const hace30 = new Date(hoy); hace30.setDate(hace30.getDate() - 30);
  const visitasHoy = visitas.filter(v => new Date(v.created_at) >= hoy).length;
  const visitas7d = visitas.filter(v => new Date(v.created_at) >= hace7).length;
  const visitas30d = visitas.filter(v => new Date(v.created_at) >= hace30).length;
  const unicosTotal = ranking.length;

  // Filtro de tiempo
  const ahora = new Date();
  const visitasFiltradas = visitas.filter(v => {
    const d = new Date(v.created_at);
    if (filtro === "hoy") return d >= hoy;
    if (filtro === "7d") return d >= hace7;
    if (filtro === "30d") return d >= hace30;
    return true;
  }).filter(v =>
    !busqueda || v.nombre?.toLowerCase().includes(busqueda.toLowerCase()) ||
    v.email?.toLowerCase().includes(busqueda.toLowerCase())
  );

  const statBox = (icon, label, value, color) => (
    <div style={{
      background: color + "12", border: `1px solid ${color}30`,
      borderRadius: 14, padding: "14px 18px", flex: 1, minWidth: 120,
    }}>
      <div style={{ fontSize: 22 }}>{icon}</div>
      <div style={{ fontSize: 24, fontWeight: 800, color, marginTop: 4 }}>{value}</div>
      <div style={{ fontSize: 11, color: C.gray, marginTop: 2 }}>{label}</div>
    </div>
  );

  const cuerdaColor = { Soprano: "#ec4899", Contralto: "#0e7490", Tenor: "#3b82f6", Bajo: "#f59e0b", Admin: "#10b981" };

  if (loading) return <FinSpinner />;

  return (
    <div>
      <div style={{ fontWeight: 700, fontSize: 16, color: C.dark, marginBottom: 4 }}>📊 Registro de Visitas</div>
      <div style={{ fontSize: 12, color: C.gray, marginBottom: 20 }}>Cuántas veces y quiénes ingresan al sitio.</div>

      {/* Stats */}
      <div style={{ display: "flex", gap: 12, flexWrap: "wrap", marginBottom: 24 }}>
        {statBox("📅", "Hoy", visitasHoy, C.primary)}
        {statBox("📆", "Últimos 7 días", visitas7d, "#3b82f6")}
        {statBox("🗓️", "Últimos 30 días", visitas30d, "#2d7dd2")}
        {statBox("♾️", "Total histórico", visitas.length, "#f59e0b")}
        {statBox("👥", "Integrantes únicos", unicosTotal, "#ec4899")}
      </div>

      {/* Online ahora */}
      <div style={{
        background: "linear-gradient(135deg,#f0fdf4,#dcfce7)",
        border: "1.5px solid #86efac",
        borderRadius: 18, padding: "16px 20px", marginBottom: 28,
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
          <span style={{
            display: "inline-block", width: 10, height: 10, borderRadius: "50%",
            background: "#22c55e",
            boxShadow: "0 0 0 3px #86efac",
            animation: "pulse 2s infinite",
          }} />
          <span style={{ fontWeight: 700, fontSize: 14, color: "#15803d" }}>
            En línea ahora — {online.length} {online.length === 1 ? "integrante" : "integrantes"}
          </span>
          <button onClick={cargarOnline} style={{
            marginLeft: "auto", fontSize: 11, padding: "3px 10px", borderRadius: 20,
            border: "1px solid #86efac", background: "white", color: "#15803d", cursor: "pointer",
          }}>🔄 Actualizar</button>
        </div>
        {online.length === 0 ? (
          <div style={{ fontSize: 12, color: "#1a4d8f", fontStyle: "italic" }}>No hay integrantes conectados en este momento.</div>
        ) : (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
            {online.map((u) => (
              <div key={u.integrante_id || u.email} style={{
                display: "flex", alignItems: "center", gap: 8,
                background: "white", borderRadius: 30, padding: "6px 12px 6px 6px",
                border: "1px solid #bbf7d0", boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
              }}>
                <div style={{
                  width: 30, height: 30, borderRadius: "50%",
                  background: cuerdaColor[u.cuerda] || C.primary,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  color: "white", fontWeight: 800, fontSize: 12, flexShrink: 0,
                }}>
                  {(u.nombre || "?")[0].toUpperCase()}
                </div>
                <div>
                  <div style={{ fontSize: 12, fontWeight: 700, color: C.dark, lineHeight: 1.2 }}>{u.nombre}</div>
                  {u.cuerda && <div style={{ fontSize: 10, color: cuerdaColor[u.cuerda] || C.gray, fontWeight: 600 }}>{u.cuerda}</div>}
                </div>
                <span style={{
                  width: 8, height: 8, borderRadius: "50%", background: "#22c55e",
                  flexShrink: 0, marginLeft: 2,
                }} />
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Ranking */}
      <div style={{ fontWeight: 700, fontSize: 13, color: C.dark, marginBottom: 10 }}>🏆 Ranking de visitas por integrante</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 28 }}>
        {ranking.slice(0, 10).map((r, i) => (
          <div key={r.email} style={{
            display: "flex", alignItems: "center", gap: 12,
            background: i === 0 ? "#fef9c3" : i === 1 ? "#f1f5f9" : i === 2 ? "#fef3e2" : C.white,
            border: `1px solid ${C.border}`, borderRadius: 12, padding: "10px 14px",
          }}>
            <div style={{ fontWeight: 800, fontSize: 16, width: 24, textAlign: "center", color: i < 3 ? ["#f59e0b","var(--text-tertiary)","#cd7c2f"][i] : C.gray }}>
              {i < 3 ? ["🥇","🥈","🥉"][i] : `${i+1}`}
            </div>
            <div style={{
              width: 34, height: 34, borderRadius: "50%", flexShrink: 0,
              background: cuerdaColor[r.cuerda] || C.primary,
              display: "flex", alignItems: "center", justifyContent: "center",
              color: "white", fontWeight: 700, fontSize: 13,
            }}>
              {(r.nombre || "?")[0].toUpperCase()}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontWeight: 600, fontSize: 13, color: C.dark }}>{r.nombre}</div>
              <div style={{ fontSize: 11, color: C.gray }}>{r.email}</div>
            </div>
            {r.cuerda && (
              <span style={{
                fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 20,
                background: (cuerdaColor[r.cuerda] || C.primary) + "20",
                color: cuerdaColor[r.cuerda] || C.primary,
              }}>{r.cuerda}</span>
            )}
            <div style={{ textAlign: "right" }}>
              <div style={{ fontWeight: 800, fontSize: 18, color: C.primary }}>{r.total}</div>
              <div style={{ fontSize: 10, color: C.gray }}>visitas</div>
            </div>
          </div>
        ))}
      </div>

      {/* Log de visitas */}
      <div style={{ fontWeight: 700, fontSize: 13, color: C.dark, marginBottom: 10 }}>📋 Registro detallado</div>
      <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap", alignItems: "center" }}>
        {[["todo","Todo"],["hoy","Hoy"],["7d","7 días"],["30d","30 días"]].map(([k,l]) => (
          <button key={k} onClick={() => setFiltro(k)} style={{
            fontSize: 12, padding: "5px 12px", borderRadius: 20, cursor: "pointer", border: "1px solid",
            fontWeight: 600,
            background: filtro === k ? C.primary : "white",
            color: filtro === k ? "white" : C.gray,
            borderColor: filtro === k ? C.primary : C.border,
          }}>{l}</button>
        ))}
        <input
          value={busqueda} onChange={e => setBusqueda(e.target.value)}
          placeholder="🔍 Buscar nombre o correo..."
          style={{
            fontSize: 12, padding: "5px 12px", borderRadius: 20, border: `1px solid ${C.border}`,
            outline: "none", minWidth: 200, color: C.dark,
          }}
        />
        <button onClick={cargar} style={{ fontSize: 11, padding: "5px 12px", borderRadius: 20, border: `1px solid ${C.border}`, cursor: "pointer", background: "white", color: C.gray }}>
          🔄 Actualizar
        </button>
      </div>

      <div style={{ maxHeight: 380, overflowY: "auto", border: `1px solid ${C.border}`, borderRadius: 10 }}>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
          <thead>
            <tr style={{ background: C.light, position: "sticky", top: 0 }}>
              {["Fecha y hora","Nombre","Correo","Cuerda"].map(h => (
                <th key={h} style={{ padding: "8px 12px", textAlign: "left", fontWeight: 700, color: C.gray, fontSize: 11, borderBottom: `1px solid ${C.border}` }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {visitasFiltradas.length === 0 ? (
              <tr><td colSpan={4} style={{ padding: 24, textAlign: "center", color: C.gray }}>Sin registros</td></tr>
            ) : visitasFiltradas.map((v, i) => (
              <tr key={v.id || i} style={{ borderBottom: `1px solid ${C.border}`, background: i % 2 === 0 ? "white" : C.light + "80" }}>
                <td style={{ padding: "7px 12px", color: C.gray, whiteSpace: "nowrap" }}>
                  {new Date(v.created_at).toLocaleString("es-CL", { day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" })}
                </td>
                <td style={{ padding: "7px 12px", fontWeight: 600, color: C.dark }}>{v.nombre}</td>
                <td style={{ padding: "7px 12px", color: C.gray }}>{v.email}</td>
                <td style={{ padding: "7px 12px" }}>
                  {v.cuerda && (
                    <span style={{
                      fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 20,
                      background: (cuerdaColor[v.cuerda] || C.primary) + "20",
                      color: cuerdaColor[v.cuerda] || C.primary,
                    }}>{v.cuerda}</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  CONFIGURACIÓN DE CLAVES API (Admin)
// ══════════════════════════════════════════════════════════════════════
function AdminApiConfig() {
  const [anthropicKey, setAnthropicKey] = useState("");
  const [guardando, setGuardando] = useState(false);
  const [msg, setMsg] = useState(null);

  useEffect(() => {
    getConfig("anthropic_api_key").then((k) => { if (k) setAnthropicKey(k); }).catch(() => {});
  }, []);

  async function guardar() {
    if (!anthropicKey.trim()) { setMsg({ ok: false, txt: "Pega primero tu clave de Anthropic." }); return; }
    setGuardando(true); setMsg(null);
    try {
      await setConfig("anthropic_api_key", anthropicKey.trim());
      _anthropicKey = anthropicKey.trim();
      setMsg({ ok: true, txt: "✓ Clave guardada. Ya funcionarán la extracción de acordes y el evangelio automático." });
    } catch { setMsg({ ok: false, txt: "Error al guardar. Intenta de nuevo." }); }
    setGuardando(false);
  }

  const inp = { width: "100%", padding: "10px 12px", borderRadius: 10, border: "1px solid rgba(60,60,67,0.2)", fontSize: 13, marginBottom: 8, boxSizing: "border-box", fontFamily: "monospace" };
  return (
    <div>
      <div style={{ fontSize: 14, fontWeight: 700, color: "#1c1c1e", marginBottom: 6 }}>🔑 Clave API de Anthropic</div>
      <div style={{ fontSize: 12.5, color: "#6a6a70", marginBottom: 14, lineHeight: 1.6 }}>
        Necesaria para que funcionen: extracción automática de acordes desde PDF, cambio de tono, y el evangelio del domingo.<br />
        Obtenla en <a href="https://console.anthropic.com/settings/keys" target="_blank" rel="noreferrer" style={{ color: "#0a5ac8" }}>console.anthropic.com → API Keys</a>. Se guarda encriptada en tu base de datos Supabase.
      </div>
      <input
        value={anthropicKey}
        onChange={(e) => setAnthropicKey(e.target.value)}
        placeholder="sk-ant-api03-…"
        type="password"
        style={inp}
      />
      <button onClick={guardar} disabled={guardando}
        style={{ background: "#0a5ac8", color: "white", border: "none", borderRadius: 10, padding: "9px 18px", fontSize: 13, fontWeight: 700, cursor: guardando ? "not-allowed" : "pointer", opacity: guardando ? 0.7 : 1 }}>
        {guardando ? "Guardando…" : "Guardar clave"}
      </button>
      {msg && <div style={{ marginTop: 10, fontSize: 12.5, color: msg.ok ? "#15803d" : "#b91c1c", lineHeight: 1.5 }}>{msg.txt}</div>}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════
//  MANTENEDOR CUENTA BANCARIA (Admin)
// ══════════════════════════════════════════════════════════════════════
function AdminCuentaBancaria() {
  const EMPTY = { nombre: "", rut: "", banco: "", tipo_cuenta: "Cuenta Vista", numero_cuenta: "", correo: "" };
  const [cuenta, setCuenta] = useState(null);
  const [form, setForm] = useState(EMPTY);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState(null);
  const [editMode, setEditMode] = useState(false);

  useEffect(() => { loadCuenta(); }, []);

  async function loadCuenta() {
    setLoading(true);
    try {
      const data = await finDbGet("fin_cuenta_bancaria");
      if (data && data.length > 0) {
        setCuenta(data[0]);
        setForm(data[0]);
      } else {
        setCuenta(null);
        setForm(EMPTY);
      }
    } catch (e) { setMsg({ type: "error", text: "Error cargando datos: " + e.message }); }
    setLoading(false);
  }

  const setF = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  async function handleSave() {
    if (!form.nombre || !form.rut || !form.banco || !form.numero_cuenta || !form.correo) {
      setMsg({ type: "error", text: "Por favor completa todos los campos obligatorios." });
      return;
    }
    setSaving(true);
    setMsg(null);
    try {
      const body = { nombre: form.nombre, rut: form.rut, banco: form.banco, tipo_cuenta: form.tipo_cuenta, numero_cuenta: form.numero_cuenta, correo: form.correo };
      if (cuenta?.id) {
        await finDbPatch("fin_cuenta_bancaria", cuenta.id, body);
      } else {
        await finDbPost("fin_cuenta_bancaria", body);
      }
      setMsg({ type: "ok", text: "✅ Cuenta bancaria guardada correctamente." });
      setEditMode(false);
      await loadCuenta();
    } catch (e) { setMsg({ type: "error", text: "Error al guardar: " + e.message }); }
    setSaving(false);
  }

  async function handleDelete() {
    if (!cuenta?.id) return;
    if (!window.confirm("¿Eliminar los datos de cuenta bancaria?")) return;
    setSaving(true);
    try {
      await finDbDelete("fin_cuenta_bancaria", cuenta.id);
      setCuenta(null);
      setForm(EMPTY);
      setEditMode(false);
      setMsg({ type: "ok", text: "Cuenta bancaria eliminada." });
    } catch (e) { setMsg({ type: "error", text: e.message }); }
    setSaving(false);
  }

  const inputStyle = {
    width: "100%", padding: "9px 12px", borderRadius: 10, border: `1px solid ${C.border}`,
    fontSize: 13, color: C.dark, background: C.white, boxSizing: "border-box", outline: "none",
  };
  const labelStyle = { fontSize: 12, fontWeight: 600, color: C.gray, marginBottom: 4, display: "block" };
  const fieldWrap = { display: "flex", flexDirection: "column", gap: 0 };

  if (loading) return <FinSpinner />;

  return (
    <div style={{ maxWidth: 600 }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 18 }}>
        <div>
          <div style={{ fontWeight: 700, fontSize: 16, color: C.dark }}>🏦 Cuenta Bancaria para Cuotas</div>
          <div style={{ fontSize: 12, color: C.gray, marginTop: 2 }}>Esta información se mostrará a todos los integrantes en "Info. Gastos".</div>
        </div>
        {cuenta && !editMode && (
          <div style={{ display: "flex", gap: 8 }}>
            <FinBtn variant="secondary" onClick={() => { setEditMode(true); setMsg(null); }}>✏️ Editar</FinBtn>
            <FinBtn variant="danger" onClick={handleDelete} disabled={saving}>🗑 Eliminar</FinBtn>
          </div>
        )}
      </div>

      {msg && (
        <div style={{
          padding: "10px 14px", borderRadius: 10, marginBottom: 14, fontSize: 13,
          background: msg.type === "ok" ? "#d1fae5" : "#fee2e2",
          color: msg.type === "ok" ? "#065f46" : "#991b1b",
          border: `1px solid ${msg.type === "ok" ? "#6ee7b7" : "#fca5a5"}`,
        }}>{msg.text}</div>
      )}

      {/* Vista de solo lectura */}
      {cuenta && !editMode && (
        <div style={{
          background: "linear-gradient(135deg,#f0fdf8,#e6f7f1)",
          border: `1px solid ${C.primary}30`,
          borderRadius: 18, padding: "20px 24px",
        }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px 24px" }}>
            {[
              ["👤 Nombre", cuenta.nombre],
              ["🪪 RUT", cuenta.rut],
              ["🏦 Banco", cuenta.banco],
              ["💳 Tipo de cuenta", cuenta.tipo_cuenta],
              ["🔢 Número de cuenta", cuenta.numero_cuenta],
              ["📧 Correo", cuenta.correo],
            ].map(([lbl, val]) => (
              <div key={lbl}>
                <div style={{ fontSize: 11, color: C.gray, fontWeight: 600 }}>{lbl}</div>
                <div style={{ fontSize: 14, color: C.dark, fontWeight: 500, marginTop: 2 }}>{val}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Sin datos */}
      {!cuenta && !editMode && (
        <div style={{ textAlign: "center", padding: "32px 0", color: C.gray }}>
          <div style={{ fontSize: 36, marginBottom: 10 }}>🏦</div>
          <div style={{ fontSize: 14, marginBottom: 16 }}>No hay cuenta bancaria registrada aún.</div>
          <FinBtn onClick={() => { setEditMode(true); setMsg(null); }}>+ Agregar cuenta bancaria</FinBtn>
        </div>
      )}

      {/* Formulario */}
      {editMode && (
        <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
            <div style={fieldWrap}>
              <label style={labelStyle}>Nombre titular *</label>
              <input style={inputStyle} value={form.nombre} onChange={(e) => setF("nombre", e.target.value)} placeholder="Ej: Juan Pérez González" />
            </div>
            <div style={fieldWrap}>
              <label style={labelStyle}>RUT *</label>
              <input style={inputStyle} value={form.rut} onChange={(e) => setF("rut", e.target.value)} placeholder="Ej: 12.345.678-9" />
            </div>
            <div style={fieldWrap}>
              <label style={labelStyle}>Banco *</label>
              <select style={inputStyle} value={form.banco} onChange={(e) => setF("banco", e.target.value)}>
                <option value="">— Selecciona el banco —</option>
                <option>ABN AMRO BANK (CHILE)</option>
                <option>BANCO BICE</option>
                <option>BANCO BCI/MACHBANK</option>
                <option>BANCO CONSORCIO</option>
                <option>BANCO DE CHILE</option>
                <option>BANCO DEL DESARROLLO</option>
                <option>BANCO DEL ESTADO DE CHILE</option>
                <option>BANCO FALABELLA</option>
                <option>BANCO INTERNACIONAL</option>
                <option>BANCO ITAU</option>
                <option>BANCO PARIS</option>
                <option>BANCO RIPLEY</option>
                <option>BANCO SANTANDER-SANTIAGO</option>
                <option>BANCO SECURITY</option>
                <option>CITIBANK N.A.</option>
                <option>COOPEUCH/DALE</option>
                <option>COPEC PAY</option>
                <option>CORPBANCA</option>
                <option>FINTUAL</option>
                <option>GLOBAL66</option>
                <option>HSBC BANK CHILE</option>
                <option>JP MORGAN</option>
                <option>LA POLAR PREPAGO</option>
                <option>MERCADO PAGO EMISORA S.A</option>
                <option>METROMUV</option>
                <option>PREPAGO LOS HEROES.</option>
                <option>PREX</option>
                <option>RABOBANK</option>
                <option>SCOTIABANK</option>
                <option>SUMUP</option>
                <option>TANNER</option>
                <option>TAPP CAJA LOS ANDES</option>
                <option>TENPO PREPAGO</option>
                <option>TRICOT PREPAGO</option>
              </select>
            </div>
            <div style={fieldWrap}>
              <label style={labelStyle}>Tipo de cuenta *</label>
              <select style={inputStyle} value={form.tipo_cuenta} onChange={(e) => setF("tipo_cuenta", e.target.value)}>
                <option value="Cuenta Vista">Cuenta Vista</option>
                <option value="Cuenta Corriente">Cuenta Corriente</option>
                <option value="Cuenta de Ahorro">Cuenta de Ahorro</option>
                <option value="Cuenta RUT">Cuenta RUT</option>
              </select>
            </div>
            <div style={fieldWrap}>
              <label style={labelStyle}>Número de cuenta *</label>
              <input style={inputStyle} value={form.numero_cuenta} onChange={(e) => setF("numero_cuenta", e.target.value)} placeholder="Ej: 00012345678" />
            </div>
            <div style={fieldWrap}>
              <label style={labelStyle}>Correo electrónico *</label>
              <input style={inputStyle} type="email" value={form.correo} onChange={(e) => setF("correo", e.target.value)} placeholder="Ej: tesorero@coro.cl" />
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, marginTop: 4 }}>
            <FinBtn onClick={handleSave} disabled={saving}>{saving ? "Guardando…" : "💾 Guardar"}</FinBtn>
            <FinBtn variant="ghost" onClick={() => { setEditMode(false); setForm(cuenta || EMPTY); setMsg(null); }}>Cancelar</FinBtn>
          </div>
        </div>
      )}


    </div>
  );
}

export function InfoGastos({ user, members }) {
  const [pagos, setPagos] = useState([]);
  const [gastos, setGastos] = useState([]);
  const [actividades, setActividades] = useState([]);
  const [cuotas, setCuotas] = useState([]);
  const [miembrosEnCuotas, setMiembrosEnCuotas] = useState([]);
  const [cuentaBancaria, setCuentaBancaria] = useState(null);
  const [loading, setLoading] = useState(true);
  const [tabActiva, setTabActiva] = useState("estado");
  const [mesVerCuotas, setMesVerCuotas] = useState("");
  const [actExpandida, setActExpandida] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const [p, g, a, c, mc, cb] = await Promise.all([
          finDbGet("fin_pagos"),
          finDbGet("fin_gastos"),
          finDbGet("fin_actividades"),
          finDbGet("fin_cuotas"),
          finDbGet("fin_miembros_cuotas"),
          finDbGet("fin_cuenta_bancaria").catch(() => []),
        ]);
        setPagos(p || []);
        setGastos(g || []);
        setActividades(a || []);
        setCuotas(c || []);
        setMiembrosEnCuotas(mc || []);
        setCuentaBancaria(cb && cb.length > 0 ? cb[0] : null);
      } catch (e) { console.error(e); }
      setLoading(false);
    })();
  }, []);

  const totalIngresado = pagos.reduce((s, p) => s + (p.monto || 0), 0);
  const totalGastado = gastos.reduce((s, g) => s + (g.monto || 0), 0);
  const saldo = totalIngresado - totalGastado;

  // Mes de cuota vigente:
  // Si hoy < día 20: la cuota vigente es el mes actual (plazo = día 20 de este mes)
  // Si hoy >= día 20: la cuota vigente es el mes siguiente (plazo = día 20 del próximo mes)
  // Ejemplo: 28 mayo (>=20) → cuota JUNIO. 1 junio (<20) → cuota JUNIO. 20 junio (>=20) → cuota JULIO.
  const _hoyIG = new Date();
  const _diaHoyIG = _hoyIG.getDate();
  const _mesVigenteDate = _diaHoyIG < 20
    ? new Date(_hoyIG.getFullYear(), _hoyIG.getMonth())
    : new Date(_hoyIG.getFullYear(), _hoyIG.getMonth() + 1);
  const mesActual = `${_mesVigenteDate.getFullYear()}-${String(_mesVigenteDate.getMonth() + 1).padStart(2, "0")}`;
  const mesVer = mesVerCuotas || mesActual;
  // El plazo de pago vence el día 20 del mes de la cuota
  const [_igAnio, _igMes] = mesVer.split("-").map(Number);
  const plazoVencimiento = new Date(_igAnio, _igMes - 1, 20);
  const mesVencidoIG = _hoyIG > plazoVencimiento;

  const cuotasActivas = mesActual >= CUOTAS_MES_INICIO || pagos.some((p) => p.tipo === "cuota");
  const pagosMesActual = pagos.filter((p) => p.mes === mesVer);
  const miembrosIds = new Set(miembrosEnCuotas.map((m) => m.integrante_id));
  const miembrosActivos = members.filter((m) => miembrosIds.has(m.id));
  const pagaron = new Set(pagosMesActual.map((p) => p.integrante_id));
  const alDia = cuotasActivas ? miembrosActivos.filter((m) => pagaron.has(m.id)) : [];
  const pendientes = cuotasActivas ? miembrosActivos.filter((m) => !pagaron.has(m.id)) : [];
  const cuotaMesActual = cuotas.find((c) => c.mes === mesVer);
  const mesesCuotaDisponibles = Array.from(new Set([...cuotas.map((c) => c.mes), ...pagos.map((p) => p.mes), mesActual].filter((m) => m && m >= CUOTAS_MES_INICIO))).sort().reverse();


  if (loading) return <FinSpinner />;

  const TABS_PUB = [
    { id: "estado", label: "💰 Estado financiero" },
    { id: "cuotas", label: "📋 Estado de cuotas" },
    { id: "mihistorial", label: "📅 Mis pagos" },
    { id: "gastos", label: "🧾 Gastos por actividad" },
  ];

  return (
    <div style={{ maxWidth: 900 }}>
      {/* Header */}
      <div
        style={{
          background: `linear-gradient(135deg,#0f4c3a,${C.primary})`,
          borderRadius: 16,
          padding: "24px 28px",
          marginBottom: 20,
          color: "white",
        }}
      >
        <div style={{ fontFamily: "var(--font-display)", fontSize: 22, fontWeight: 700, marginBottom: 4 }}>
          📊 Información de Gastos
        </div>
        <div style={{ fontSize: 13, opacity: 0.85 }}>
          Transparencia financiera del Coro Misioneros de Jesús
        </div>
      </div>

      {/* Resumen rápido */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(180px,1fr))", gap: 12, marginBottom: 20 }}>
        <StatCard icon="💰" label="Saldo disponible" value={finFmtCLP(saldo)} color={saldo >= 0 ? C.primary : "#ef4444"} />
        <StatCard icon="📥" label="Total ingresado" value={finFmtCLP(totalIngresado)} color="#3b82f6" />
        <StatCard icon="📤" label="Total gastado" value={finFmtCLP(totalGastado)} color="#f59e0b" />
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 16, paddingBottom: 4 }}>
        {TABS_PUB.map((t) => (
          <TabBtn key={t.id} label={t.label} active={tabActiva === t.id} onClick={() => setTabActiva(t.id)} />
        ))}
      </div>

      {/* Estado financiero */}
      {tabActiva === "estado" && (
        <FinCard>
          <div style={{ fontWeight: 600, fontSize: 15, color: C.dark, marginBottom: 14 }}>
            Movimientos por mes
          </div>
          {[...new Set(pagos.map((p) => p.mes))].sort().reverse().map((mes) => {
            const ing = pagos.filter((p) => p.mes === mes).reduce((s, p) => s + (p.monto || 0), 0);
            const cuota = cuotas.find((c) => c.mes === mes);
            const cant = pagos.filter((p) => p.mes === mes && p.tipo === "cuota").length;
            return (
              <div key={mes} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 0", borderBottom: `1px solid ${C.border}` }}>
                <div>
                  <div style={{ fontWeight: 600, color: C.dark, fontSize: 14 }}>{finMesLabel(mes)}</div>
                  <div style={{ fontSize: 11, color: C.gray }}>
                    {cant} pago{cant !== 1 ? "s" : ""}
                    {cuota ? ` · ${finFmtCLP(cuota.valor)} c/u` : ""}
                  </div>
                </div>
                <div style={{ fontWeight: 700, color: C.primary }}>{finFmtCLP(ing)}</div>
              </div>
            );
          })}
          {pagos.length === 0 && <div style={{ fontSize: 13, color: C.gray }}>Sin movimientos registrados.</div>}
        </FinCard>
      )}

      {/* Estado de cuotas */}
      {tabActiva === "cuotas" && (
        !cuotasActivas ? (
          <FinCard>
            <div style={{ textAlign: "center", padding: "20px 0", color: C.gray, fontSize: 13 }}>
              <div style={{ fontSize: 28, marginBottom: 8 }}>📅</div>
              <div style={{ fontWeight: 600, color: C.dark, marginBottom: 4 }}>Las cuotas aún no han comenzado</div>
              <div>El sistema de cuotas se activa a partir de <strong>Junio 2026</strong>.</div>
            </div>
          </FinCard>
        ) : (
        <div>
          <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
            <span style={{ fontSize: 12.5, color: C.gray, fontWeight: 600 }}>Ver mes:</span>
            <select value={mesVer} onChange={(e) => setMesVerCuotas(e.target.value)} style={{ fontSize: 13, padding: "7px 11px", borderRadius: 9, border: `1px solid ${C.border}`, background: "white", color: C.dark, fontWeight: 600 }}>
              {mesesCuotaDisponibles.map((m) => (<option key={m} value={m}>{finMesLabel(m)}</option>))}
            </select>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <FinCard>
            <div style={{ fontWeight: 700, color: C.primary, fontSize: 14, marginBottom: 4 }}>
              ✅ Al día — {finMesLabel(mesVer)}
              {cuotaMesActual && <span style={{ fontSize: 11, fontWeight: 400, color: C.gray }}> · {finFmtCLP(cuotaMesActual.valor)}</span>}
            </div>
            {miembrosEnCuotas.some((r) => r.es_estudiante) && (
              <div style={{ fontSize: 11, color: "#0369a1", background: "#e0f2fe", borderRadius: 8, padding: "5px 9px", marginBottom: 10, lineHeight: 1.5 }}>
                🎓 Los integrantes marcados como <strong>Estudiante</strong> pagan una cuota rebajada de <strong>$3.000</strong>.
              </div>
            )}
            {alDia.length === 0 ? (
              <div style={{ fontSize: 12, color: C.gray }}>Ninguno ha pagado aún.</div>
            ) : alDia.map((m) => {
              const pagoM = pagosMesActual.find(p => p.integrante_id === m.id);
              const esEst = miembrosEnCuotas.find((r) => r.integrante_id === m.id)?.es_estudiante;
              return (
                <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6, padding: "6px 8px", borderRadius: 10, background: C.bg }}>
                  <Avatar nombre={m.nombre} foto_url={m.foto_url} size={28} color={C.primary} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, display: "flex", alignItems: "center", gap: 5, flexWrap: "wrap" }}>
                      {m.nombre}
                      {esEst && (
                        <span style={{ fontSize: 10, fontWeight: 700, background: "#e0f2fe", color: "#0369a1", borderRadius: 20, padding: "1px 6px" }}>🎓 Estudiante</span>
                      )}
                    </div>
                    {pagoM?.monto && (
                      <div style={{ fontSize: 10, color: C.gray }}>{finFmtCLP(pagoM.monto)}</div>
                    )}
                  </div>
                  {pagoM?.comprobante_url ? (
                    pagoM.comprobante_url.startsWith("texto:") ? (
                      <span title={pagoM.comprobante_url.replace("texto:", "")} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 11, color: "#0369a1", background: "#e0f2fe", padding: "3px 8px", borderRadius: 16, fontWeight: 600, cursor: "help" }}>
                        📝 Nota
                      </span>
                    ) : (
                    <a
                      href={pagoM.comprobante_url}
                      target="_blank"
                      rel="noreferrer"
                      title="Ver comprobante"
                      style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 11, color: C.primary, textDecoration: "none", background: C.primary + "15", padding: "3px 8px", borderRadius: 16, fontWeight: 600 }}
                    >
                      📎 Comprobante
                    </a>
                    )
                  ) : (
                    <span style={{ fontSize: 10, color: C.gray, background: "#f1f5f9", padding: "2px 7px", borderRadius: 10 }}>Sin comprobante</span>
                  )}
                </div>
              );
            })}
          </FinCard>
          <FinCard>
            <div style={{ fontWeight: 700, color: mesVencidoIG ? "#ef4444" : "#f59e0b", fontSize: 14, marginBottom: 12 }}>
              {mesVencidoIG ? "⚠️ Morosos" : "🕐 Plazo vigente"} — {finMesLabel(mesVer)}
            </div>
            {!mesVencidoIG ? (
              <div style={{ fontSize: 12, color: C.gray, lineHeight: 1.6 }}>
                <div style={{ marginBottom: 6 }}>El plazo de pago aún está abierto.</div>
                <div>Cada integrante puede pagar hasta el <strong>día 20 de {finMesLabel(mesVer)}</strong>.</div>
                <div style={{ marginTop: 8, padding: "6px 10px", background: "#fef9c3", borderRadius: 10, color: "#92400e", fontSize: 11 }}>
                  💡 Quienes ya aparecen como &quot;Al día&quot; pagaron de forma anticipada.
                </div>
              </div>
            ) : pendientes.length === 0 ? (
              <div style={{ fontSize: 12, color: C.gray }}>¡Todos han pagado! 🎉</div>
            ) : pendientes.map((m) => (
              <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                <Avatar nombre={m.nombre} foto_url={m.foto_url} size={28} color="#ef4444" />
                <span style={{ fontSize: 13 }}>{m.nombre}</span>
              </div>
            ))}
          </FinCard>
        </div>
        </div>
        )
      )}

      {/* Mis pagos — historial personal del integrante */}
      {tabActiva === "mihistorial" && (() => {
        const misPagos = (pagos || [])
          .filter((p) => p.integrante_id === user?.id)
          .sort((a, b) => (b.mes || "").localeCompare(a.mes || ""));
        const totalMio = misPagos.reduce((s, p) => s + (p.monto || 0), 0);
        return (
          <div>
            <div style={{ background: "linear-gradient(180deg,#f5f9ff,#eaf2ff)", border: "1px solid #cfe0fb", borderRadius: 14, padding: "14px 16px", marginBottom: 14 }}>
              <div style={{ fontSize: 11, fontWeight: 800, color: "#0a5ac8", letterSpacing: "0.06em", textTransform: "uppercase" }}>Mi historial de cuotas</div>
              <div style={{ fontSize: 13.5, color: "#3a5a80", marginTop: 3 }}>
                Has realizado <b>{misPagos.length}</b> pago{misPagos.length !== 1 ? "s" : ""} — total aportado: <b>{finFmtCLP(totalMio)}</b>
              </div>
            </div>
            {misPagos.length === 0 ? (
              <div style={{ background: "white", border: "1px dashed rgba(60,60,67,0.2)", borderRadius: 14, padding: "28px 16px", textAlign: "center", color: C.gray, fontSize: 14 }}>
                Aún no tienes pagos registrados.
              </div>
            ) : (
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {misPagos.map((p) => (
                  <div key={p.id} style={{ background: "white", border: "1px solid rgba(60,60,67,0.12)", borderRadius: 12, padding: "12px 15px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 10, flexWrap: "wrap" }}>
                    <div>
                      <div style={{ fontSize: 15, fontWeight: 700, color: C.dark }}>{finMesLabel(p.mes)}</div>
                      <div style={{ fontSize: 12.5, color: C.gray }}>{finFmtCLP(p.monto || 0)}{p.tipo && p.tipo !== "cuota" ? ` · ${p.tipo}` : ""}</div>
                    </div>
                    {p.comprobante_url ? (
                      p.comprobante_url.startsWith("texto:") ? (
                        <span title={p.comprobante_url.replace("texto:", "")}
                          style={{ fontSize: 12.5, fontWeight: 700, color: "#0369a1", textDecoration: "none", border: "1px solid #bae6fd", background: "#e0f2fe", borderRadius: 9, padding: "7px 12px", cursor: "help" }}>
                          📝 Nota de pago
                        </span>
                      ) : (
                      <a href={p.comprobante_url} target="_blank" rel="noreferrer"
                        style={{ fontSize: 12.5, fontWeight: 700, color: "#0a5ac8", textDecoration: "none", border: "1px solid #cfe0fb", background: "#eaf2ff", borderRadius: 9, padding: "7px 12px" }}>
                        📎 Ver comprobante
                      </a>
                      )
                    ) : (
                      <span style={{ fontSize: 12, color: "#9a9aa0", fontStyle: "italic" }}>Sin comprobante</span>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })()}

      {/* Gastos por actividad */}
      {tabActiva === "gastos" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {actividades.length === 0 && (
            <div style={{ fontSize: 13, color: C.gray, padding: "20px 0" }}>Sin actividades registradas.</div>
          )}
          {actividades.map((a) => {
            const gastosA = gastos.filter((g) => g.actividad_id === a.id);
            const totalA = gastosA.reduce((s, g) => s + (g.monto || 0), 0);
            const expanded = actExpandida === a.id;
            const esAsadoInfo = a.tipo_actividad === "asado";
            const npInfo = a.num_personas || 0;
            const cuotaAvg = (esAsadoInfo && npInfo > 0) ? Math.round(totalA / npInfo) : null;
            return (
              <FinCard key={a.id} style={{ padding: 0, overflow: "hidden" }}>
                <div
                  onClick={() => setActExpandida(expanded ? null : a.id)}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    padding: "14px 18px",
                    cursor: "pointer",
                    background: expanded ? C.primary + "08" : "white",
                  }}
                >
                  <div>
                    <div style={{ fontWeight: 600, color: C.dark, fontSize: 14 }}>
                      {esAsadoInfo ? "🔥 " : "🎉 "}{a.nombre}
                    </div>
                    {a.fecha && <div style={{ fontSize: 11, color: C.gray }}>{a.fecha}</div>}
                    {cuotaAvg !== null && (
                      <div style={{ fontSize: 11, color: "#c2410c", fontWeight: 600, marginTop: 2 }}>
                        Costo por persona: {finFmtCLP(cuotaAvg)} · {npInfo} asistentes
                      </div>
                    )}
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                    <div style={{ fontWeight: 700, color: "#ef4444" }}>{finFmtCLP(totalA)}</div>
                    <span style={{ color: C.gray }}>{expanded ? "▲" : "▼"}</span>
                  </div>
                </div>
                {expanded && gastosA.length > 0 && (
                  <div style={{ padding: "0 18px 14px" }}>
                    {gastosA.map((g) => (
                      <div key={g.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0", borderBottom: `1px solid ${C.border}` }}>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 13, color: C.dark }}>{g.descripcion}</div>
                          <div style={{ fontSize: 11, color: C.gray }}>{g.created_at?.split("T")[0]}</div>
                        </div>
                        <div style={{ fontWeight: 600, color: "#ef4444", fontSize: 13 }}>{finFmtCLP(g.monto)}</div>
                        {g.boleta_url && (
                          <a href={g.boleta_url} target="_blank" rel="noreferrer" style={{ color: C.primary, fontSize: 13, textDecoration: "none" }}>
                            📎 Ver boleta
                          </a>
                        )}
                      </div>
                    ))}
                  </div>
                )}
                {expanded && gastosA.length === 0 && (
                  <div style={{ padding: "8px 18px 14px", fontSize: 12, color: C.gray }}>Sin gastos registrados.</div>
                )}
              </FinCard>
            );
          })}
        </div>
      )}

      {/* ── Datos de transferencia ── */}
      {cuentaBancaria && (
        <div style={{ marginTop: 24 }}>
          <FinCard style={{
            background: "linear-gradient(135deg,#f0fdf8,#e6f7f1)",
            border: `1.5px solid ${C.primary}40`,
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14 }}>
              <span style={{ fontSize: 22 }}>🏦</span>
              <div>
                <div style={{ fontWeight: 700, fontSize: 15, color: C.dark }}>Datos para transferencia de cuotas</div>
                <div style={{ fontSize: 11, color: C.gray }}>Usa estos datos para pagar tu cuota mensual</div>
              </div>
            </div>
            <div style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))",
              gap: "10px 20px",
            }}>
              {[
                ["👤 Nombre", cuentaBancaria.nombre],
                ["🪪 RUT", cuentaBancaria.rut],
                ["🏦 Banco", cuentaBancaria.banco],
                ["💳 Tipo de cuenta", cuentaBancaria.tipo_cuenta],
                ["🔢 Número de cuenta", cuentaBancaria.numero_cuenta],
                ["📧 Correo", cuentaBancaria.correo],
              ].map(([lbl, val]) => (
                <div key={lbl} style={{
                  background: "white",
                  borderRadius: 12,
                  padding: "10px 14px",
                  border: `1px solid ${C.border}`,
                }}>
                  <div style={{ fontSize: 11, color: C.gray, fontWeight: 600, marginBottom: 3 }}>{lbl}</div>
                  <div style={{
                    fontSize: 13,
                    fontWeight: 700,
                    color: C.dark,
                    display: "flex",
                    alignItems: "center",
                    gap: 6,
                  }}>
                    {val}
                    <button
                      title="Copiar"
                      onClick={() => copiarTexto(val)}
                      style={{
                        background: "none", border: "none", cursor: "pointer",
                        padding: "1px 4px", borderRadius: 7, fontSize: 12,
                        color: C.gray, opacity: 0.7,
                      }}
                    >📋</button>
                  </div>
                </div>
              ))}
            </div>
            <div style={{
              marginTop: 12,
              padding: "8px 14px",
              background: C.primary + "12",
              borderRadius: 10,
              fontSize: 12,
              color: C.primary,
              fontWeight: 500,
            }}>
              💡 Recuerda indicar tu nombre completo en el comentario de la transferencia y enviar el comprobante al tesorero.
            </div>
          </FinCard>
        </div>
      )}
    </div>
  );
}
