/*
-- 1. Agregar columna "tipo" a pautas_misa (si no existe)
ALTER TABLE pautas_misa
  ADD COLUMN IF NOT EXISTS tipo TEXT NOT NULL DEFAULT 'grupo';
-- Valores: 'grupo' (solo coro) | 'parroquial' (visible para Visita)

-- Visibilidad de columnas URL por pauta
ALTER TABLE pautas_misa ADD COLUMN IF NOT EXISTS mostrar_col_letra BOOLEAN NOT NULL DEFAULT false;
ALTER TABLE pautas_misa ADD COLUMN IF NOT EXISTS mostrar_col_audio BOOLEAN NOT NULL DEFAULT false;
-- Coro que canta la pauta (para distinguir pautas de invitados):
ALTER TABLE pautas_misa ADD COLUMN IF NOT EXISTS coro TEXT DEFAULT 'Coro Misioneros de Jesús';

-- 2. Crear el usuario invitado en Supabase Auth
-- Ve a Supabase > Authentication > Users > Add User:
--   Email:    invitado@coromj.cl   (o el que prefieras)
--   Password: (la que quieras compartir con los encargados de misa)
--   Confirm email: ✓ (marcar como confirmado)

-- 3. Insertar el perfil de integrante para el usuario invitado
-- (reemplaza el auth_id con el UUID que aparece al crear el usuario en Supabase Auth)
INSERT INTO integrantes (nombre, email, cuerda, auth_id)
VALUES ('Invitado', 'invitado@coromj.cl', 'Visita', 'PEGA_AQUI_EL_UUID_DEL_USUARIO')
ON CONFLICT (email) DO UPDATE SET cuerda = 'Visita';

-- 4. (Opcional) Si quieres que varias personas usen la misma cuenta,
--    simplemente comparte el email y contraseña del usuario invitado.
--    La sesión se puede usar en múltiples dispositivos simultáneamente.

-- 5. Marcar una pauta como parroquial (visible para Visita):
UPDATE pautas_misa SET tipo = 'parroquial' WHERE id = 'ID_DE_LA_PAUTA';
-- O hazlo directamente desde el formulario de edición en el portal (Admin).

-- 6. TABLA CONFIG (para widgets Video Destacado y Vocalización)
--    Si aún no tienes esta tabla, créala:
CREATE TABLE IF NOT EXISTS config (
  key   TEXT PRIMARY KEY,
  value TEXT
);
ALTER TABLE config ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Acceso total" ON config FOR ALL USING (true) WITH CHECK (true);

-- 7. SALA DE ENSAYO (repertorio por canto + pistas por voz)
--    Agrega columnas a material_ensayo para organizar el repertorio por canto.
--    Los archivos existentes (sin canto) caen en el grupo "General", nada se rompe.
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS canto   TEXT;
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS momento TEXT;
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS orden   INTEGER;
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS letra_texto TEXT;
-- Ficha del canto (para la tarjeta tipo Canto Católico): Autor, YouTube, Spotify, Material adicional
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS autor        TEXT;
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS youtube      TEXT;
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS spotify      TEXT;
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS material_url TEXT;
-- Audiencia: separa el repertorio del Coro vs del Invitado ('coro' | 'invitado' | 'ambos')
-- El material que ya tienes cargado (con voces) es del Invitado, por eso el default es 'invitado':
ALTER TABLE material_ensayo ADD COLUMN IF NOT EXISTS audiencia TEXT DEFAULT 'invitado';
-- Tipo de episodio de podcast: 'podcast' (temas varios) vs 'vocalizacion' (ejercicios de canto)
ALTER TABLE podcasts ADD COLUMN IF NOT EXISTS tipo TEXT DEFAULT 'podcast';
-- Material del CORO (independiente del invitado; NO se borra tras la misa). Misma estructura.
CREATE TABLE IF NOT EXISTS material_coro (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nombre TEXT, canto TEXT, momento TEXT, orden INTEGER, url TEXT,
  categoria TEXT, cuerda_mat TEXT, descripcion TEXT, size TEXT,
  letra_texto TEXT, autor TEXT, youtube TEXT, spotify TEXT, material_url TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE material_coro ENABLE ROW LEVEL SECURITY;
CREATE POLICY "material_coro_all" ON material_coro FOR ALL USING (true) WITH CHECK (true);
-- Cancioneros (PDF) del perfil Invitado: se suben y se borran tras la misa. Independiente del material por canto.
CREATE TABLE IF NOT EXISTS cancioneros_pdf (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nombre TEXT, url TEXT, size TEXT, created_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE cancioneros_pdf ENABLE ROW LEVEL SECURITY;
CREATE POLICY "cancioneros_pdf_all" ON cancioneros_pdf FOR ALL USING (true) WITH CHECK (true);
-- Repertorio del CORO leído desde Google Drive (en desuso)
CREATE TABLE IF NOT EXISTS repertorio_drive (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  canto TEXT, cuerda_mat TEXT, categoria TEXT, nombre TEXT,
  url TEXT, drive_id TEXT, audiencia TEXT DEFAULT 'coro',
  created_at TIMESTAMPTZ DEFAULT now()
);
ALTER TABLE repertorio_drive ENABLE ROW LEVEL SECURITY;
CREATE POLICY "repertorio_drive_all" ON repertorio_drive FOR ALL USING (true) WITH CHECK (true);
-- Cómo cargar: por cada canto sube un archivo por voz, repitiendo el mismo
-- "canto" y eligiendo Cuerda/Voz (Soprano/Contralto/Tenor/Bajo/Instrumentos o Todas)
-- y Categoría (Audio = pista de práctica, Letras, Partituras, Video).
*/
